(246, 118, 'vexa256@gmail.com', NULL, 'EMAIL', 'PHEIC_ADVISORY', '▣ PHEIC pathway · Ebola Virus Disease (EVD) · Uganda · IHR NFP 24h window', '\n  IHR 2005 · PHEIC PATHWAY\n  Public Health Emergency of International Concern — WHO coordination pathway.\n  ▣ DEMO_183022 — candidate PHEIC event\n  Suspected VHF — returned traveller from DRC North Kivu\n\n\n\n  A suspected case consistent with a WHO Tier 1 always-notifiable disease has been recorded. Under IHR 2005 this may constitute a PHEIC. The national IHR NFP must complete the Annex 2 assessment and notify WHO within 24 hours of the event being known.\n\n\n\n  Why PHEIC path applies\n  \n    Diseas', '<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"></head><body style=\"margin:0;padding:0;background:#EEF2F7;font-family:Arial,Helvetica,sans-serif;color:#0F172A;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#EEF2F7;padding:24px 12px;\"><tr><td align=\"center\"><table role=\"presentation\" width=\"640\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:640px;background:#FFFFFF;border-radius:10px;overflow:hidden;box-shadow:0 4px 16px rgba(15,23,42,0.08);\"><tr><td style=\"background:linear-gradient(135deg,#1E1B4B 0%,#3730A3 55%,#6D28D9 100%);padding:26px 28px;\">\n  <div style=\"font-size:11px;letter-spacing:0.22em;text-transform:uppercase;color:#DDD6FE;font-weight:700;\">IHR 2005 · PHEIC PATHWAY</div>\n  <div style=\"margin-top:6px;font-size:12px;color:#E0E7FF;font-weight:600;\">Public Health Emergency of International Concern — WHO coordination pathway.</div>\n  <div style=\"margin-top:12px;font-size:22px;font-weight:800;color:#FFFFFF;line-height:1.15;\">▣ DEMO_183022 — candidate PHEIC event</div>\n  <div style=\"margin-top:8px;font-size:13px;color:#DDD6FE;\">Suspected VHF — returned traveller from DRC North Kivu</div>\n</td></tr>\n\n<tr><td style=\"padding:22px 28px 0;\">\n  <p style=\"margin:0;font-size:13px;color:#0F172A;\">A suspected case consistent with a WHO Tier 1 always-notifiable disease has been recorded. Under IHR 2005 this may constitute a PHEIC. The national IHR NFP must complete the Annex 2 assessment and notify WHO within 24 hours of the event being known.</p>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#3730A3;font-weight:800;\">Why PHEIC path applies</div>\n  <ul style=\"margin:8px 0 0 20px;padding:0;font-size:13px;color:#0F172A;\">\n    <li style=\"margin:4px 0;\">Disease <strong>Ebola Virus Disease (EVD)</strong> is classified IHR Annex 2 — Epidemic-Prone (VHF).</li>\n    <li style=\"margin:4px 0;\">Historical CFR: 50.0%; incubation window: 2–21 days (typically 4–10).</li>\n    <li style=\"margin:4px 0;\">Transmission: Direct contact with body fluids of symptomatic case or contaminated fomites; sexual transmission from survivors; bat reservoir — plausible international spread via LAND BUS-KBZ-2314.</li>\n    <li style=\"margin:4px 0;\">Travel path: DR Congo → Goma → MUTUKULA, Uganda.</li>\n  </ul>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#3730A3;font-weight:800;\">WHO PHEIC workflow expected</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;background:#EEF2FF;border:1px solid #C7D2FE;border-radius:8px;\">\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#3730A3;font-weight:700;width:28%;\">0–24 h</td><td style=\"padding:8px 12px;font-size:12px;\">Complete Annex 2 assessment. Notify WHO via national IHR NFP.</td></tr>\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#3730A3;font-weight:700;\">24–48 h</td><td style=\"padding:8px 12px;font-size:12px;\">WHO risk assessment + follow-up questions; consider IHR Emergency Committee.</td></tr>\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#3730A3;font-weight:700;\">48 h+</td><td style=\"padding:8px 12px;font-size:12px;\">If 2+ Annex 2 criteria confirmed → WHO DG may declare PHEIC, issue temporary recommendations.</td></tr>\n  </table>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#FEF3C7;border-left:4px solid #B45309;border-radius:6px;margin:12px 0;\">\n  <tr><td style=\"padding:14px 16px;\">\n    <div style=\"font-size:11px;text-transform:uppercase;letter-spacing:0.08em;color:#92400E;font-weight:700;\">Disease intelligence</div>\n    <div style=\"font-size:17px;font-weight:700;color:#0F172A;margin:4px 0 2px;\">Ebola Virus Disease (EVD)</div>\n    <div style=\"font-size:12px;color:#475569;margin-bottom:10px;\">IHR Annex 2 — Epidemic-Prone (VHF)</div>\n    <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"font-size:12px;color:#0F172A;\">\n      <tr><td style=\"padding:3px 0;color:#64748B;\">Case fatality rate</td><td style=\"padding:3px 0;text-align:right;font-weight:700;\">50.0%</td></tr>\n      <tr><td style=\"padding:3px 0;color:#64748B;\">Incubation</td><td style=\"padding:3px 0;text-align:right;\">2–21 days (typically 4–10)</td></tr>\n      <tr><td style=\"padding:3px 0;color:#64748B;vertical-align:top;\">Transmission</td><td style=\"padding:3px 0;text-align:right;\">Direct contact with body fluids of symptomatic case or contaminated fomites; sexual transmission from survivors; bat reservoir</td></tr>\n      <tr><td style=\"padding:3px 0;color:#64748B;vertical-align:top;\">PPE</td><td style=\"padding:3px 0;text-align:right;\">VHF full PPE: fluid-resistant coverall, double gloves, PAPR or N95+face shield, hood, boots, apron</td></tr>\n      <tr><td style=\"padding:3px 0;color:#64748B;vertical-align:top;\">Isolation</td><td style=\"padding:3px 0;text-align:right;\">Dedicated VHF isolation ward / treatment centre with buddy-system PPE donning/doffing</td></tr>\n      <tr><td style=\"padding:3px 0;color:#64748B;vertical-align:top;\">IHR notification</td><td style=\"padding:3px 0;text-align:right;\">IMMEDIATE — any suspected VHF is a public health event of potential international concern</td></tr>\n    </table>\n    <div style=\"margin-top:10px;font-size:12px;color:#0F172A;\"><strong>WHO case definition:</strong> Acute fever ≥38°C and ≥3 of: headache, vomiting, anorexia, diarrhoea, lethargy, abdominal pain, muscle/joint pain, difficulty swallowing, difficulty breathing, hiccup, OR unexplained bleeding, OR contact with suspected/confirmed case within 21 days.</div>\n    <div style=\"margin-top:6px;font-size:12px;color:#0F172A;\"><strong>Differential:</strong> Marburg, Lassa, CCHF, severe malaria, typhoid, meningococcaemia, severe dengue</div>\n  </td></tr>\n</table></td></tr>\n\n<tr><td style=\"padding:0 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#3730A3;font-weight:800;\">Case snapshot</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;border:1px solid #E2E8F0;border-radius:6px;background:#F8FAFC;\">\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Traveller</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;font-weight:700;\">A. O. · 34 y · FEMALE · Uganda</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Travel</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">ENTRY · DR Congo → Goma</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Conveyance · seat</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">LAND BUS-KBZ-2314 · seat 14B</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Arrival</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">2026-04-21 12:30</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Syndrome</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">VIRAL_HAEMORRHAGIC_FEVER</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Disposition</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">ISOLATED</td></tr>\n  </table>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#3730A3;font-weight:800;\">Cross-border spread signal (travel history)</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#EEF2FF;border:1px solid #C7D2FE;border-radius:6px;\"><ul style=\"margin:0;padding-left:18px;\"><li style=\"margin:4px 0;font-size:13px;\"><strong>VISITED</strong> · DR Congo <span style=\"color:#64748B;\">(2026-04-03 → 2026-04-19)</span></li><li style=\"margin:4px 0;font-size:13px;\"><strong>TRANSIT</strong> · Rwanda <span style=\"color:#64748B;\">(2026-04-19 → 2026-04-20)</span></li></ul></div>\n</td></tr>\n\n<tr><td style=\"padding:20px 28px 14px;\">\n  <div style=\"background:#3730A3;border-radius:8px;padding:14px 16px;text-align:center;\">\n    <a href=\"http://localhost/#/active-alerts\" style=\"color:#FFFFFF;font-size:14px;font-weight:700;text-decoration:none;\">Open PHEIC assessment workflow →</a>\n  </div>\n</td></tr>\n<tr><td style=\"padding:18px 28px 12px;background:#F1F5F9;border-top:1px solid #E2E8F0;\">\n  <p style=\"margin:0;font-size:11px;color:#475569;line-height:1.5;\">\n    <strong>Uganda POE Sentinel</strong> · PHEIC · IHR 2005 · WHO IHR 2005 &amp; AFRO IDSR 3rd Ed. aligned.<br>\n    Alert <strong>DEMO_183022</strong> · CRITICAL — life-threatening · fired 30 minutes ago at 2026-04-21 18:00.<br>\n    Open in console → <a href=\"http://localhost/#/active-alerts\" style=\"color:#1D4ED8;text-decoration:none;font-weight:600;\">http://localhost/#/active-alerts</a>\n  </p>\n</td></tr>\n<tr><td style=\"padding:8px 28px 18px;background:#F1F5F9;\">\n  <p style=\"margin:0;font-size:10px;color:#64748B;line-height:1.4;\">\n    This is a transactional public-health alert generated by the national surveillance pipeline. Do not reply; coordinate through the escalation ladder.<br>\n    Generated 2026-04-21 18:30 UTC · template DEMO_183022 · recipient action expected within 4h.\n  </p>\n</td></tr></table></td></tr></table></body></html>', 'ALERT', 21, 'UG', 'KYOTERA', 'MUTUKULA', 'SENT', NULL, 0, '2026-04-21 18:31:05', NULL, NULL, 'CMD:demo-all', '2026-04-21 18:31:05', '2026-04-21 18:31:05'),
