--
-- Table structure for table `notification_templates`
--

CREATE TABLE `notification_templates` (
  `id` bigint UNSIGNED NOT NULL,
  `template_code` varchar(60) NOT NULL,
  `channel` enum('EMAIL','SMS','PUSH') NOT NULL DEFAULT 'EMAIL',
  `subject_template` varchar(200) NOT NULL,
  `body_html_template` text NOT NULL,
  `body_text_template` text,
  `applicable_levels` json DEFAULT NULL,
  `is_ai_enhanced` tinyint(1) NOT NULL DEFAULT '0',
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

--
-- Dumping data for table `notification_templates`
--

INSERT INTO `notification_templates` (`id`, `template_code`, `channel`, `subject_template`, `body_html_template`, `body_text_template`, `applicable_levels`, `is_ai_enhanced`, `is_active`, `created_at`, `updated_at`) VALUES
(1, 'ALERT_CRITICAL', 'EMAIL', '⛔ CRITICAL · {{alert_code}} · {{disease_name}} · POE {{poe_code}} · act within {{ack_hours}}h', '<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"></head><body style=\"margin:0;padding:0;background:#EEF2F7;font-family:Arial,Helvetica,sans-serif;color:#0F172A;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#EEF2F7;padding:24px 12px;\"><tr><td align=\"center\"><table role=\"presentation\" width=\"640\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:640px;background:#FFFFFF;border-radius:10px;overflow:hidden;box-shadow:0 4px 16px rgba(15,23,42,0.08);\"><tr><td style=\"background:linear-gradient(135deg,#7F1D1D 0%,#B91C1C 60%,#DC2626 100%);padding:24px 28px;\">\n  <div style=\"font-size:11px;letter-spacing:0.18em;text-transform:uppercase;color:#FECACA;font-weight:700;\">{{country_name}} · POE SENTINEL · IHR 2005</div>\n  <div style=\"margin-top:6px;font-size:12px;color:#FECACA;font-weight:600;\">CRITICAL PUBLIC HEALTH ALERT · acknowledge within {{ack_hours}} hours</div>\n  <div style=\"margin-top:10px;font-size:26px;font-weight:800;color:#FFFFFF;line-height:1.15;\">⛔ {{alert_title}}</div>\n  <div style=\"margin-top:6px;font-size:14px;color:#FECACA;\">{{summary}}</div>\n  <div style=\"margin-top:14px;background:rgba(0,0,0,0.28);border:1px solid rgba(255,255,255,0.2);border-radius:6px;padding:10px 14px;\">\n    <div style=\"font-size:11px;text-transform:uppercase;letter-spacing:0.08em;color:#FFFFFF;opacity:0.9;\">Acknowledge by</div>\n    <div style=\"font-size:15px;color:#FFFFFF;font-weight:700;margin-top:2px;\">{{ack_deadline}} ({{ack_hours}}h SLA)</div>\n    <div style=\"font-size:12px;color:#FECACA;margin-top:4px;\">Escalation path: {{escalation_ladder}}</div>\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:22px 28px 6px;\">\n  <p style=\"margin:0;font-size:13px;color:#0F172A;\">This alert was raised because a patient at the named Point of Entry meets CRITICAL surveillance criteria under IHR 2005 and national IDSR guidance. Full case dossier, disease intelligence, and the exact actions expected of you follow below.</p>\n</td></tr>\n\n<tr><td style=\"padding:18px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#B91C1C;font-weight:800;\">WHAT · WHERE · WHO</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;border:1px solid #FEE2E2;border-radius:8px;background:#FEF2F2;\">\n    <tr><td style=\"padding:8px 12px;border-bottom:1px solid #FEE2E2;font-size:12px;color:#7F1D1D;\">Alert code</td><td style=\"padding:8px 12px;border-bottom:1px solid #FEE2E2;font-size:13px;text-align:right;font-weight:700;color:#7F1D1D;\">{{alert_code}}</td></tr>\n    <tr><td style=\"padding:8px 12px;border-bottom:1px solid #FEE2E2;font-size:12px;color:#7F1D1D;\">Risk classification</td><td style=\"padding:8px 12px;border-bottom:1px solid #FEE2E2;font-size:13px;text-align:right;font-weight:700;color:#B91C1C;\">{{risk_level_label}}</td></tr>\n    <tr><td style=\"padding:8px 12px;border-bottom:1px solid #FEE2E2;font-size:12px;color:#7F1D1D;\">Point of Entry · District</td><td style=\"padding:8px 12px;border-bottom:1px solid #FEE2E2;font-size:13px;text-align:right;font-weight:700;\">{{poe_code}} · {{district_code}}</td></tr>\n    <tr><td style=\"padding:8px 12px;border-bottom:1px solid #FEE2E2;font-size:12px;color:#7F1D1D;\">Country · Province</td><td style=\"padding:8px 12px;border-bottom:1px solid #FEE2E2;font-size:13px;text-align:right;\">{{country_name}} · {{province_code}}</td></tr>\n    <tr><td style=\"padding:8px 12px;border-bottom:1px solid #FEE2E2;font-size:12px;color:#7F1D1D;\">Detected by</td><td style=\"padding:8px 12px;border-bottom:1px solid #FEE2E2;font-size:13px;text-align:right;\">{{captured_by_name}} → case opened by {{opened_by_name}}</td></tr>\n    <tr><td style=\"padding:8px 12px;border-bottom:1px solid #FEE2E2;font-size:12px;color:#7F1D1D;\">Detected at · Case opened</td><td style=\"padding:8px 12px;border-bottom:1px solid #FEE2E2;font-size:13px;text-align:right;\">{{captured_at}} · {{opened_at}}</td></tr>\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#7F1D1D;\">Alert status</td><td style=\"padding:8px 12px;font-size:13px;text-align:right;font-weight:700;\">{{alert_status}}</td></tr>\n  </table>\n</td></tr>\n\n<tr><td style=\"padding:18px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#7F1D1D;font-weight:800;\">ACT RIGHT NOW · CRITICAL</div>\n  <div style=\"margin-top:6px;padding:12px 14px;background:#FFFFFF;border:2px solid #B91C1C;border-radius:8px;\">\n    {{{immediate_actions_html}}}\n    <p style=\"margin:10px 0 0;font-size:12px;color:#7F1D1D;font-style:italic;\">⚠ These actions are time-critical. Any delay breaches the IHR 2005 notification window and the national 7-1-7 response target.</p>\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:18px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#B91C1C;font-weight:800;\">WHO · traveller profile</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;border:1px solid #E2E8F0;border-radius:8px;background:#F8FAFC;\">\n    <tr><td style=\"padding:8px 12px;border-bottom:1px solid #E2E8F0;font-size:12px;color:#475569;\">Name · Age · Gender</td><td style=\"padding:8px 12px;border-bottom:1px solid #E2E8F0;font-size:13px;text-align:right;\"><strong>{{traveler_name}}</strong> · {{traveler_age}} · {{traveler_gender}}</td></tr>\n    <tr><td style=\"padding:8px 12px;border-bottom:1px solid #E2E8F0;font-size:12px;color:#475569;\">Nationality · Occupation</td><td style=\"padding:8px 12px;border-bottom:1px solid #E2E8F0;font-size:13px;text-align:right;\">{{traveler_nationality}} · {{traveler_occupation}}</td></tr>\n    <tr><td style=\"padding:8px 12px;border-bottom:1px solid #E2E8F0;font-size:12px;color:#475569;\">Residence</td><td style=\"padding:8px 12px;border-bottom:1px solid #E2E8F0;font-size:13px;text-align:right;\">{{traveler_residence}}</td></tr>\n    <tr><td style=\"padding:8px 12px;border-bottom:1px solid #E2E8F0;font-size:12px;color:#475569;\">Reach · Emergency contact</td><td style=\"padding:8px 12px;border-bottom:1px solid #E2E8F0;font-size:13px;text-align:right;\">{{traveler_phone}} / {{traveler_email}} · {{emergency_contact}}</td></tr>\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#475569;\">Destination in country</td><td style=\"padding:8px 12px;font-size:13px;text-align:right;\">{{destination_district}} — {{destination_address}}</td></tr>\n  </table>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#B91C1C;font-weight:800;\">WHEN · HOW · travel exposure</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;border:1px solid #E2E8F0;border-radius:8px;background:#F8FAFC;\">\n    <tr><td style=\"padding:8px 12px;border-bottom:1px solid #E2E8F0;font-size:12px;color:#475569;\">Direction · Purpose · Stay</td><td style=\"padding:8px 12px;border-bottom:1px solid #E2E8F0;font-size:13px;text-align:right;\">{{travel_direction}} · {{purpose_of_travel}} · {{length_of_stay}}</td></tr>\n    <tr><td style=\"padding:8px 12px;border-bottom:1px solid #E2E8F0;font-size:12px;color:#475569;\">Journey start · Embarkation</td><td style=\"padding:8px 12px;border-bottom:1px solid #E2E8F0;font-size:13px;text-align:right;\">{{journey_start}} · {{embarkation_port}}</td></tr>\n    <tr><td style=\"padding:8px 12px;border-bottom:1px solid #E2E8F0;font-size:12px;color:#475569;\">Conveyance · Seat</td><td style=\"padding:8px 12px;border-bottom:1px solid #E2E8F0;font-size:13px;text-align:right;\">{{conveyance_type}} {{conveyance_id}} · seat {{seat_number}}</td></tr>\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#475569;\">Arrival · Departure</td><td style=\"padding:8px 12px;font-size:13px;text-align:right;\">{{arrival_datetime}} → {{departure_datetime}}</td></tr>\n  </table>\n  <div style=\"margin-top:10px;padding:10px 12px;background:#F8FAFC;border-left:3px solid #B91C1C;\">\n    <div style=\"font-size:11px;text-transform:uppercase;color:#475569;font-weight:700;\">Countries traversed</div>\n    <div style=\"margin-top:4px;\">{{{travel_html}}}</div>\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#B91C1C;font-weight:800;\">CLINICAL PICTURE</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;border:1px solid #E2E8F0;border-radius:8px;background:#F8FAFC;\">\n    <tr><td style=\"padding:8px 12px;border-bottom:1px solid #E2E8F0;font-size:12px;color:#475569;\">Triage · General appearance</td><td style=\"padding:8px 12px;border-bottom:1px solid #E2E8F0;font-size:13px;text-align:right;font-weight:700;\">{{triage_category}} · {{general_appearance}}</td></tr>\n    <tr><td style=\"padding:8px 12px;border-bottom:1px solid #E2E8F0;font-size:12px;color:#475569;\">Emergency signs</td><td style=\"padding:8px 12px;border-bottom:1px solid #E2E8F0;font-size:13px;text-align:right;font-weight:700;color:#B91C1C;\">{{emergency_signs}}</td></tr>\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#475569;\">Syndromic classification</td><td style=\"padding:8px 12px;font-size:13px;text-align:right;\">{{syndrome_classification}}</td></tr>\n    {{{vitals_html}}}\n  </table>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#B91C1C;font-weight:800;\">SYMPTOMS · ({{symptoms_count}} recorded)</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:8px;\">{{{symptoms_html}}}</div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#B91C1C;font-weight:800;\">KEY EXPOSURES</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:8px;\">{{{exposures_html}}}</div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#B91C1C;font-weight:800;\">WHY · Differential ({{suspected_count}})</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:8px;\">{{{suspected_html}}}</div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">{{{disease_intel_html}}}</td></tr>\n\n<tr><td style=\"padding:0 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#B91C1C;font-weight:800;\">Recommended tests · specimens</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:8px;\">\n    {{{recommended_tests_html}}}\n    <p style=\"margin:10px 0 0;font-size:12px;color:#475569;\"><strong>Specimens to collect:</strong> {{disease_specimens}}</p>\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#B91C1C;font-weight:800;\">Bedside red flags</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:8px;\">{{{key_distinguishers_html}}}</div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#B91C1C;font-weight:800;\">Samples collected ({{samples_count}})</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:8px;\">{{{samples_html}}}</div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#B91C1C;font-weight:800;\">Officer disposition + notes</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:8px;\">\n    <p style=\"margin:0 0 6px;font-size:13px;\"><strong>Disposition:</strong> {{final_disposition}} <span style=\"color:#64748B;\">({{disposition_details}})</span></p>\n    <p style=\"margin:0 0 6px;font-size:13px;\"><strong>Outcome:</strong> {{screening_outcome}} · follow-up required: {{followup_required}} → {{followup_level}}</p>\n    <p style=\"margin:0;font-size:13px;color:#0F172A;\"><em>{{officer_notes}}</em></p>\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#B91C1C;font-weight:800;\">Required follow-ups ({{followups_count}} · {{followups_overdue_count}} overdue)</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:8px;\">{{{followups_html}}}</div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#B91C1C;font-weight:800;\">Context · prior alerts at {{poe_code}} (last 30 days)</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:8px;\">{{{prior_alerts_html}}}</div>\n</td></tr>\n\n<tr><td style=\"padding:20px 28px 14px;\">\n  <div style=\"background:#B91C1C;border-radius:8px;padding:14px 16px;text-align:center;\">\n    <a href=\"{{console_url}}\" style=\"color:#FFFFFF;font-size:14px;font-weight:700;text-decoration:none;\">Open {{alert_code}} in POE Sentinel console →</a>\n  </div>\n</td></tr>\n<tr><td style=\"padding:18px 28px 12px;background:#F1F5F9;border-top:1px solid #E2E8F0;\">\n  <p style=\"margin:0;font-size:11px;color:#475569;line-height:1.5;\">\n    <strong>{{country_name}} POE Sentinel</strong> · CRITICAL ALERT · WHO IHR 2005 &amp; AFRO IDSR 3rd Ed. aligned.<br>\n    Alert <strong>{{alert_code}}</strong> · {{risk_level_label}} · fired {{alert_created_ago}} at {{alert_created_at}}.<br>\n    Open in console → <a href=\"{{console_url}}\" style=\"color:#1D4ED8;text-decoration:none;font-weight:600;\">{{console_url}}</a>\n  </p>\n</td></tr>\n<tr><td style=\"padding:8px 28px 18px;background:#F1F5F9;\">\n  <p style=\"margin:0;font-size:10px;color:#64748B;line-height:1.4;\">\n    This is a transactional public-health alert generated by the national surveillance pipeline. Do not reply; coordinate through the escalation ladder.<br>\n    Generated {{now}} UTC · template {{alert_code}} · recipient action expected within {{ack_sla_hours}}h.\n  </p>\n</td></tr></table></td></tr></table></body></html>', 'POE SENTINEL — CRITICAL ALERT\n{{alert_code}} · {{country_name}} · POE {{poe_code}} · District {{district_code}}\nTitle: {{alert_title}}\nSummary: {{summary}}\n\nACT NOW — acknowledge within {{ack_hours}} hours (by {{ack_deadline}})\nEscalation ladder: {{escalation_ladder}}\n\nWHO: {{traveler_name}} · {{traveler_age}} · {{traveler_gender}} · {{traveler_nationality}} · occupation {{traveler_occupation}}\nResidence: {{traveler_residence}} · reach {{traveler_phone}} / {{traveler_email}}\nDestination in country: {{destination_district}} ({{destination_address}})\n\nTRAVEL: {{travel_direction}} via {{conveyance_type}} {{conveyance_id}} seat {{seat_number}}\nJourney start {{journey_start}} → embarkation {{embarkation_port}}\nArrival {{arrival_datetime}} · departure {{departure_datetime}}\nPurpose {{purpose_of_travel}} · planned stay {{length_of_stay}}\n\nCLINICAL: triage {{triage_category}} · general appearance {{general_appearance}} · emergency signs {{emergency_signs}}\nSyndrome: {{syndrome_classification}}\nDisposition: {{final_disposition}} ({{disposition_details}})\nOfficer notes: {{officer_notes}}\n\nDISEASE INTEL: {{disease_name}} — {{disease_who_category}}\n · CFR {{disease_cfr_pct}}   · Incubation {{disease_incubation}}\n · Transmission: {{disease_transmission}}\n · PPE: {{disease_ppe}}\n · Isolation: {{disease_isolation}}\n · IHR notification: {{disease_ihr_notification}}\n · Case definition: {{disease_case_definition}}\n · Differential: {{disease_differential}}\n · Specimens: {{disease_specimens}}\n\nOPEN IN CONSOLE → {{console_url}}\nAlert created {{alert_created_at}} ({{alert_created_ago}}). Status {{alert_status}}.\n{{country_name}} POE Sentinel · WHO IHR 2005 + AFRO IDSR 2021.', '[\"DISTRICT\", \"PHEOC\", \"NATIONAL\", \"WHO\"]', 0, 1, '2026-04-21 18:15:56', '2026-04-21 18:15:56'),
(2, 'ALERT_HIGH', 'EMAIL', '⚠ HIGH · {{alert_code}} · {{disease_name}} · POE {{poe_code}}', '<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"></head><body style=\"margin:0;padding:0;background:#EEF2F7;font-family:Arial,Helvetica,sans-serif;color:#0F172A;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#EEF2F7;padding:24px 12px;\"><tr><td align=\"center\"><table role=\"presentation\" width=\"640\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:640px;background:#FFFFFF;border-radius:10px;overflow:hidden;box-shadow:0 4px 16px rgba(15,23,42,0.08);\"><tr><td style=\"background:linear-gradient(135deg,#92400E 0%,#D97706 60%,#F59E0B 100%);padding:24px 28px;\">\n  <div style=\"font-size:11px;letter-spacing:0.18em;text-transform:uppercase;color:#FEF3C7;font-weight:700;\">{{country_name}} · POE SENTINEL · IHR 2005</div>\n  <div style=\"margin-top:6px;font-size:12px;color:#FEF3C7;font-weight:600;\">HIGH-risk public health alert · acknowledge within {{ack_hours}} hours</div>\n  <div style=\"margin-top:10px;font-size:24px;font-weight:800;color:#FFFFFF;line-height:1.15;\">⚠ {{alert_title}}</div>\n  <div style=\"margin-top:6px;font-size:14px;color:#FEF3C7;\">{{summary}}</div>\n</td></tr>\n\n<tr><td style=\"padding:20px 28px 4px;\">\n  <p style=\"margin:0;font-size:13px;color:#0F172A;\">A HIGH-risk public-health event has been flagged at {{poe_code}}. Review the case dossier, confirm disposition, and escalate to {{routed_to_level}} per the national ladder. Acknowledge in the console within {{ack_sla_hours}} hours to maintain the 7-1-7 response window.</p>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"background:#FEF3C7;border:1px solid #FCD34D;border-radius:8px;padding:12px 14px;\">\n    <div style=\"font-size:11px;text-transform:uppercase;letter-spacing:0.08em;color:#92400E;font-weight:800;\">Situation at a glance</div>\n    <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;font-size:12px;\">\n      <tr><td style=\"padding:3px 0;color:#78350F;\">Alert</td><td style=\"padding:3px 0;text-align:right;font-weight:700;\">{{alert_code}}</td></tr>\n      <tr><td style=\"padding:3px 0;color:#78350F;\">Risk</td><td style=\"padding:3px 0;text-align:right;font-weight:700;color:#B45309;\">{{risk_level_label}}</td></tr>\n      <tr><td style=\"padding:3px 0;color:#78350F;\">Location</td><td style=\"padding:3px 0;text-align:right;\">POE {{poe_code}} · {{district_code}} · {{country_name}}</td></tr>\n      <tr><td style=\"padding:3px 0;color:#78350F;\">Detected by</td><td style=\"padding:3px 0;text-align:right;\">{{captured_by_name}} at {{captured_at}}</td></tr>\n      <tr><td style=\"padding:3px 0;color:#78350F;\">Case opened by</td><td style=\"padding:3px 0;text-align:right;\">{{opened_by_name}} at {{opened_at}}</td></tr>\n      <tr><td style=\"padding:3px 0;color:#78350F;\">Acknowledge by</td><td style=\"padding:3px 0;text-align:right;font-weight:700;\">{{ack_deadline}}</td></tr>\n      <tr><td style=\"padding:3px 0;color:#78350F;\">Ladder</td><td style=\"padding:3px 0;text-align:right;\">{{escalation_ladder}}</td></tr>\n    </table>\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:18px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#92400E;font-weight:800;\">Traveller profile</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;font-size:12px;\">\n    <tr><td style=\"padding:4px 0;color:#475569;\">Identity</td><td style=\"padding:4px 0;text-align:right;font-weight:700;\">{{traveler_name}} · {{traveler_age}} · {{traveler_gender}}</td></tr>\n    <tr><td style=\"padding:4px 0;color:#475569;\">Nationality · Residence</td><td style=\"padding:4px 0;text-align:right;\">{{traveler_nationality}} · {{traveler_residence}}</td></tr>\n    <tr><td style=\"padding:4px 0;color:#475569;\">Occupation</td><td style=\"padding:4px 0;text-align:right;\">{{traveler_occupation}}</td></tr>\n    <tr><td style=\"padding:4px 0;color:#475569;\">Destination</td><td style=\"padding:4px 0;text-align:right;\">{{destination_district}} · {{destination_address}}</td></tr>\n    <tr><td style=\"padding:4px 0;color:#475569;\">Reach</td><td style=\"padding:4px 0;text-align:right;\">{{traveler_phone}} · {{traveler_email}}</td></tr>\n  </table>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#92400E;font-weight:800;\">Travel history</div>\n  <div style=\"margin-top:8px;padding:10px 14px;background:#FFFBEB;border:1px solid #FCD34D;border-radius:8px;\">\n    <p style=\"margin:0 0 4px;font-size:12px;color:#78350F;\">{{travel_direction}} · {{conveyance_type}} {{conveyance_id}} · seat {{seat_number}} · arrival {{arrival_datetime}}</p>\n    {{{travel_html}}}\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#92400E;font-weight:800;\">Clinical picture</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;background:#FFFBEB;border:1px solid #FCD34D;border-radius:8px;\">\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#78350F;\">Triage · general appearance</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;font-weight:700;\">{{triage_category}} · {{general_appearance}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#78350F;\">Emergency signs</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;font-weight:700;color:#B45309;\">{{emergency_signs}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#78350F;\">Syndrome</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{syndrome_classification}}</td></tr>\n    {{{vitals_html}}}\n  </table>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#92400E;font-weight:800;\">Symptoms ({{symptoms_count}}) &amp; exposures</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#FFFBEB;border:1px solid #FCD34D;border-radius:8px;\">\n    {{{symptoms_html}}}\n    <hr style=\"border:none;border-top:1px dashed #FCD34D;margin:10px 0;\">\n    {{{exposures_html}}}\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#92400E;font-weight:800;\">Differential ({{suspected_count}})</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#FFFBEB;border:1px solid #FCD34D;border-radius:8px;\">{{{suspected_html}}}</div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">{{{disease_intel_html}}}</td></tr>\n\n<tr><td style=\"padding:0 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#92400E;font-weight:800;\">Immediate actions</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#FFFFFF;border:2px solid #F59E0B;border-radius:8px;\">\n    {{{immediate_actions_html}}}\n    <p style=\"margin:10px 0 0;font-size:12px;color:#92400E;\">Recommended tests: see below. Collect specimens per disease protocol: <strong>{{disease_specimens}}</strong>.</p>\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#92400E;font-weight:800;\">Recommended tests</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#FFFBEB;border:1px solid #FCD34D;border-radius:8px;\">{{{recommended_tests_html}}}</div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#92400E;font-weight:800;\">Samples &amp; follow-ups</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#FFFBEB;border:1px solid #FCD34D;border-radius:8px;\">\n    <p style=\"margin:0 0 6px;font-size:12px;color:#78350F;\"><strong>Samples recorded ({{samples_count}})</strong></p>\n    {{{samples_html}}}\n    <hr style=\"border:none;border-top:1px dashed #FCD34D;margin:10px 0;\">\n    <p style=\"margin:0 0 6px;font-size:12px;color:#78350F;\"><strong>Follow-up actions ({{followups_count}} seeded · {{followups_overdue_count}} overdue)</strong></p>\n    {{{followups_html}}}\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#92400E;font-weight:800;\">Context · prior alerts at {{poe_code}}</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#FFFBEB;border:1px solid #FCD34D;border-radius:8px;\">{{{prior_alerts_html}}}</div>\n</td></tr>\n\n<tr><td style=\"padding:20px 28px 14px;\">\n  <div style=\"background:#D97706;border-radius:8px;padding:14px 16px;text-align:center;\">\n    <a href=\"{{console_url}}\" style=\"color:#FFFFFF;font-size:14px;font-weight:700;text-decoration:none;\">Open {{alert_code}} in POE Sentinel →</a>\n  </div>\n</td></tr>\n<tr><td style=\"padding:18px 28px 12px;background:#F1F5F9;border-top:1px solid #E2E8F0;\">\n  <p style=\"margin:0;font-size:11px;color:#475569;line-height:1.5;\">\n    <strong>{{country_name}} POE Sentinel</strong> · HIGH-RISK ALERT · WHO IHR 2005 &amp; AFRO IDSR 3rd Ed. aligned.<br>\n    Alert <strong>{{alert_code}}</strong> · {{risk_level_label}} · fired {{alert_created_ago}} at {{alert_created_at}}.<br>\n    Open in console → <a href=\"{{console_url}}\" style=\"color:#1D4ED8;text-decoration:none;font-weight:600;\">{{console_url}}</a>\n  </p>\n</td></tr>\n<tr><td style=\"padding:8px 28px 18px;background:#F1F5F9;\">\n  <p style=\"margin:0;font-size:10px;color:#64748B;line-height:1.4;\">\n    This is a transactional public-health alert generated by the national surveillance pipeline. Do not reply; coordinate through the escalation ladder.<br>\n    Generated {{now}} UTC · template {{alert_code}} · recipient action expected within {{ack_sla_hours}}h.\n  </p>\n</td></tr></table></td></tr></table></body></html>', 'POE SENTINEL — HIGH-RISK ALERT\n{{alert_code}} · {{country_name}} · POE {{poe_code}}\n{{alert_title}}\n\n{{summary}}\n\nAcknowledge by {{ack_deadline}} ({{ack_hours}}h). Ladder: {{escalation_ladder}}.\n\nTRAVELLER: {{traveler_name}} · {{traveler_age}} · {{traveler_gender}} · {{traveler_nationality}}\nTravel: {{travel_direction}} {{conveyance_type}} {{conveyance_id}} seat {{seat_number}} · arrival {{arrival_datetime}}\nPurpose {{purpose_of_travel}} · stay {{length_of_stay}}\nDestination: {{destination_district}} — {{destination_address}}\n\nCLINICAL: {{triage_category}} · {{general_appearance}} · emergency signs {{emergency_signs}}\nSyndrome: {{syndrome_classification}}\nDisposition: {{final_disposition}} ({{disposition_details}})\n\nDISEASE: {{disease_name}} ({{disease_who_category}})\nCFR {{disease_cfr_pct}} · Incubation {{disease_incubation}}\nTransmission: {{disease_transmission}}\nPPE: {{disease_ppe}}\nIsolation: {{disease_isolation}}\nIHR: {{disease_ihr_notification}}\nCase def: {{disease_case_definition}}\nDifferential: {{disease_differential}}\nSpecimens: {{disease_specimens}}\n\nFollow-ups: {{followups_count}} seeded, {{followups_overdue_count}} overdue.\nOpen in console → {{console_url}}', '[\"DISTRICT\", \"PHEOC\", \"NATIONAL\"]', 0, 1, '2026-04-21 18:15:56', '2026-04-21 18:15:56'),
(3, 'TIER1_ADVISORY', 'EMAIL', '⚕ IHR Tier 1 · {{disease_name}} suspected · {{country_name}} POE {{poe_code}} · 24h WHO window', '<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"></head><body style=\"margin:0;padding:0;background:#EEF2F7;font-family:Arial,Helvetica,sans-serif;color:#0F172A;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#EEF2F7;padding:24px 12px;\"><tr><td align=\"center\"><table role=\"presentation\" width=\"640\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:640px;background:#FFFFFF;border-radius:10px;overflow:hidden;box-shadow:0 4px 16px rgba(15,23,42,0.08);\"><tr><td style=\"background:linear-gradient(135deg,#0C1B3A 0%,#1E293B 55%,#0F172A 100%);padding:26px 28px;\">\n  <div style=\"font-size:11px;letter-spacing:0.22em;text-transform:uppercase;color:#FCD34D;font-weight:700;\">IHR 2005 · TIER 1 · ALWAYS NOTIFIABLE</div>\n  <div style=\"margin-top:6px;font-size:12px;color:#E2E8F0;font-weight:600;\">A single suspected case triggers WHO notification within 24 hours.</div>\n  <div style=\"margin-top:12px;font-size:22px;font-weight:800;color:#FFFFFF;line-height:1.15;\">⚕ {{disease_name}} — suspected case</div>\n  <div style=\"margin-top:8px;font-size:14px;color:#E2E8F0;\">{{alert_title}}</div>\n  <div style=\"margin-top:14px;padding:10px 14px;background:rgba(252,211,77,0.12);border:1px solid rgba(252,211,77,0.3);border-radius:6px;\">\n    <div style=\"font-size:12px;color:#FDE68A;\"><strong>{{country_name}}</strong> · POE {{poe_code}} · {{district_code}} · alert {{alert_code}}</div>\n    <div style=\"font-size:12px;color:#FCD34D;margin-top:4px;\">Status {{alert_status}} · raised {{alert_created_at}}</div>\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:22px 28px 0;\">\n  <p style=\"margin:0;font-size:13px;color:#0F172A;\"><strong>Regulatory context.</strong> Under the International Health Regulations (2005), <em>{{disease_name}}</em> is in the WHO <strong>Tier 1 always-notifiable</strong> list. A single laboratory-confirmed OR clinically-suspected case constitutes a potential Public Health Emergency of International Concern and must be notified to WHO through the National IHR Focal Point within <strong>24 hours of detection</strong>.</p>\n</td></tr>\n\n<tr><td style=\"padding:16px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#0C1B3A;font-weight:800;\">Disease profile — {{disease_name}}</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F1F5F9;border-left:4px solid #FCD34D;border-radius:6px;\">\n    <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"font-size:12px;\">\n      <tr><td style=\"padding:3px 0;color:#475569;\">WHO category</td><td style=\"padding:3px 0;text-align:right;font-weight:700;\">{{disease_who_category}}</td></tr>\n      <tr><td style=\"padding:3px 0;color:#475569;\">Case fatality rate</td><td style=\"padding:3px 0;text-align:right;font-weight:700;\">{{disease_cfr_pct}}</td></tr>\n      <tr><td style=\"padding:3px 0;color:#475569;\">Incubation</td><td style=\"padding:3px 0;text-align:right;\">{{disease_incubation}}</td></tr>\n      <tr><td style=\"padding:3px 0;color:#475569;vertical-align:top;\">Transmission</td><td style=\"padding:3px 0;text-align:right;\">{{disease_transmission}}</td></tr>\n      <tr><td style=\"padding:3px 0;color:#475569;vertical-align:top;\">PPE required</td><td style=\"padding:3px 0;text-align:right;\">{{disease_ppe}}</td></tr>\n      <tr><td style=\"padding:3px 0;color:#475569;vertical-align:top;\">Isolation</td><td style=\"padding:3px 0;text-align:right;\">{{disease_isolation}}</td></tr>\n      <tr><td style=\"padding:3px 0;color:#475569;vertical-align:top;\">IHR notification window</td><td style=\"padding:3px 0;text-align:right;color:#B91C1C;font-weight:700;\">{{disease_ihr_notification}}</td></tr>\n    </table>\n    <p style=\"margin:10px 0 0;font-size:12px;color:#0F172A;\"><strong>WHO case definition:</strong> {{disease_case_definition}}</p>\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:16px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#0C1B3A;font-weight:800;\">Tier 1 response protocol</div>\n  <ol style=\"margin:10px 0 0 20px;padding:0;font-size:13px;color:#0F172A;\">\n    <li style=\"margin:6px 0;\"><strong>Immediate isolation</strong> of the suspected case per the disease-specific posture ({{disease_isolation}}).</li>\n    <li style=\"margin:6px 0;\"><strong>Full PPE</strong> for all subsequent contact ({{disease_ppe}}).</li>\n    <li style=\"margin:6px 0;\"><strong>Stop onward transport</strong> — conveyance {{conveyance_type}} {{conveyance_id}}, seat {{seat_number}}. Quarantine contacts.</li>\n    <li style=\"margin:6px 0;\"><strong>National IHR NFP notification</strong> within 24h. Risk assessment under Annex 2.</li>\n    <li style=\"margin:6px 0;\"><strong>Laboratory confirmation</strong> — specimens: {{disease_specimens}}.</li>\n    <li style=\"margin:6px 0;\"><strong>Contact tracing</strong> based on disease incubation ({{disease_incubation}}).</li>\n    <li style=\"margin:6px 0;\"><strong>Public risk communication</strong> coordinated with national MoH / WHO country office.</li>\n  </ol>\n</td></tr>\n\n<tr><td style=\"padding:16px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#0C1B3A;font-weight:800;\">Case dossier</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;border:1px solid #E2E8F0;border-radius:6px;background:#F8FAFC;\">\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Traveller</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;font-weight:700;\">{{traveler_name}} · {{traveler_age}} · {{traveler_gender}} · {{traveler_nationality}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Occupation · residence</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{traveler_occupation}} · {{traveler_residence}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Travel</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{travel_direction}} · {{journey_start}} → {{embarkation_port}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Conveyance</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{conveyance_type}} {{conveyance_id}} · seat {{seat_number}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Timing</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">arrival {{arrival_datetime}} · detected {{captured_at}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Clinical</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">triage {{triage_category}} · emergency signs {{emergency_signs}}</td></tr>\n  </table>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">{{{vitals_html_wrap}}}\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#0C1B3A;font-weight:800;\">Vitals</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;border:1px solid #E2E8F0;border-radius:6px;background:#F8FAFC;\">{{{vitals_html}}}</table>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#0C1B3A;font-weight:800;\">Symptoms ({{symptoms_count}}) + exposures</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:6px;\">\n    {{{symptoms_html}}}<hr style=\"border:none;border-top:1px dashed #E2E8F0;margin:10px 0;\">{{{exposures_html}}}\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#0C1B3A;font-weight:800;\">Red-flag findings — bedside</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:6px;\">{{{key_distinguishers_html}}}</div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#0C1B3A;font-weight:800;\">Differential diagnosis ({{suspected_count}} ranked)</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:6px;\">\n    {{{suspected_html}}}\n    <p style=\"margin:10px 0 0;font-size:12px;color:#475569;\"><strong>Standard differential to exclude:</strong> {{disease_differential}}.</p>\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#0C1B3A;font-weight:800;\">Immediate actions</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#0F172A;border-radius:6px;\">\n    <div style=\"color:#FCD34D;font-size:11px;text-transform:uppercase;letter-spacing:0.08em;font-weight:700;\">Execute now · non-negotiable</div>\n    <div style=\"margin-top:8px;\">{{{immediate_actions_html}}}</div>\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#0C1B3A;font-weight:800;\">Follow-ups ({{followups_count}} · {{followups_overdue_count}} overdue)</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:6px;\">{{{followups_html}}}</div>\n</td></tr>\n\n<tr><td style=\"padding:20px 28px 14px;\">\n  <div style=\"background:linear-gradient(135deg,#1E293B 0%,#0F172A 100%);border-radius:8px;padding:14px 16px;text-align:center;\">\n    <a href=\"{{console_url}}\" style=\"color:#FCD34D;font-size:14px;font-weight:700;text-decoration:none;\">Acknowledge {{alert_code}} in POE Sentinel →</a>\n  </div>\n</td></tr>\n<tr><td style=\"padding:18px 28px 12px;background:#F1F5F9;border-top:1px solid #E2E8F0;\">\n  <p style=\"margin:0;font-size:11px;color:#475569;line-height:1.5;\">\n    <strong>{{country_name}} POE Sentinel</strong> · IHR TIER 1 ADVISORY · WHO IHR 2005 &amp; AFRO IDSR 3rd Ed. aligned.<br>\n    Alert <strong>{{alert_code}}</strong> · {{risk_level_label}} · fired {{alert_created_ago}} at {{alert_created_at}}.<br>\n    Open in console → <a href=\"{{console_url}}\" style=\"color:#1D4ED8;text-decoration:none;font-weight:600;\">{{console_url}}</a>\n  </p>\n</td></tr>\n<tr><td style=\"padding:8px 28px 18px;background:#F1F5F9;\">\n  <p style=\"margin:0;font-size:10px;color:#64748B;line-height:1.4;\">\n    This is a transactional public-health alert generated by the national surveillance pipeline. Do not reply; coordinate through the escalation ladder.<br>\n    Generated {{now}} UTC · template {{alert_code}} · recipient action expected within {{ack_sla_hours}}h.\n  </p>\n</td></tr></table></td></tr></table></body></html>', 'POE SENTINEL — IHR TIER 1 ADVISORY\n{{disease_name}} — suspected case\n{{country_name}} · POE {{poe_code}} · alert {{alert_code}}\n\nREGULATORY: under IHR 2005, {{disease_name}} is in the WHO Tier 1 always-notifiable list.\nSingle suspected case → notify WHO via national IHR NFP within 24h.\n\nDISEASE PROFILE:\n · WHO category: {{disease_who_category}}\n · CFR: {{disease_cfr_pct}}\n · Incubation: {{disease_incubation}}\n · Transmission: {{disease_transmission}}\n · PPE: {{disease_ppe}}\n · Isolation: {{disease_isolation}}\n · IHR window: {{disease_ihr_notification}}\n · Case definition: {{disease_case_definition}}\n · Differential: {{disease_differential}}\n · Specimens: {{disease_specimens}}\n\nCASE: {{traveler_name}} · {{traveler_age}} · {{traveler_gender}} · {{traveler_nationality}}\nTravel: {{travel_direction}} · {{journey_start}} → {{embarkation_port}} · {{conveyance_type}} {{conveyance_id}} seat {{seat_number}}\nArrival {{arrival_datetime}} · detected {{captured_at}}\nClinical: triage {{triage_category}} · emergency signs {{emergency_signs}} · syndrome {{syndrome_classification}}\n\nFollow-ups seeded: {{followups_count}} ({{followups_overdue_count}} overdue).\nOpen in console → {{console_url}}', '[\"NATIONAL\", \"WHO\"]', 0, 1, '2026-04-21 18:15:56', '2026-04-21 18:15:56');
INSERT INTO `notification_templates` (`id`, `template_code`, `channel`, `subject_template`, `body_html_template`, `body_text_template`, `applicable_levels`, `is_ai_enhanced`, `is_active`, `created_at`, `updated_at`) VALUES
(4, 'ANNEX2_HIT', 'EMAIL', '◆ IHR Annex 2 criteria met · {{disease_name}} · {{country_name}} POE {{poe_code}}', '<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"></head><body style=\"margin:0;padding:0;background:#EEF2F7;font-family:Arial,Helvetica,sans-serif;color:#0F172A;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#EEF2F7;padding:24px 12px;\"><tr><td align=\"center\"><table role=\"presentation\" width=\"640\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:640px;background:#FFFFFF;border-radius:10px;overflow:hidden;box-shadow:0 4px 16px rgba(15,23,42,0.08);\"><tr><td style=\"background:linear-gradient(135deg,#4C1D95 0%,#5B21B6 55%,#7C3AED 100%);padding:26px 28px;\">\n  <div style=\"font-size:11px;letter-spacing:0.22em;text-transform:uppercase;color:#E9D5FF;font-weight:700;\">IHR 2005 · ANNEX 2 DECISION INSTRUMENT</div>\n  <div style=\"margin-top:6px;font-size:12px;color:#EDE9FE;font-weight:600;\">Event may constitute a public-health emergency of international concern.</div>\n  <div style=\"margin-top:12px;font-size:22px;font-weight:800;color:#FFFFFF;line-height:1.15;\">◆ Annex 2 criteria met — assess &amp; notify</div>\n  <div style=\"margin-top:8px;font-size:14px;color:#EDE9FE;\">{{alert_title}}</div>\n</td></tr>\n\n<tr><td style=\"padding:22px 28px 0;\">\n  <p style=\"margin:0;font-size:13px;color:#0F172A;\">This event was flagged against the WHO IHR Annex 2 Decision Instrument. At least one Annex 2 pillar has fired and a national risk assessment is required. If 2 or more criteria are confirmed, the event must be notified to WHO through the National IHR Focal Point.</p>\n</td></tr>\n\n<tr><td style=\"padding:16px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#5B21B6;font-weight:800;\">The four Annex 2 criteria</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;background:#F5F3FF;border:1px solid #DDD6FE;border-radius:8px;\">\n    <tr>\n      <td style=\"padding:10px 14px;border-bottom:1px solid #DDD6FE;\">\n        <div style=\"font-size:11px;text-transform:uppercase;letter-spacing:0.06em;color:#6D28D9;font-weight:700;\">1 · Serious public-health impact</div>\n        <div style=\"font-size:12px;color:#0F172A;margin-top:2px;\">High case-fatality, rapid progression, vulnerable populations, healthcare system strain.</div>\n      </td>\n    </tr>\n    <tr>\n      <td style=\"padding:10px 14px;border-bottom:1px solid #DDD6FE;\">\n        <div style=\"font-size:11px;text-transform:uppercase;letter-spacing:0.06em;color:#6D28D9;font-weight:700;\">2 · Unusual / unexpected</div>\n        <div style=\"font-size:12px;color:#0F172A;margin-top:2px;\">Unknown aetiology, unusual clinical course, unexpected geographical spread, emergence of resistance.</div>\n      </td>\n    </tr>\n    <tr>\n      <td style=\"padding:10px 14px;border-bottom:1px solid #DDD6FE;\">\n        <div style=\"font-size:11px;text-transform:uppercase;letter-spacing:0.06em;color:#6D28D9;font-weight:700;\">3 · Significant risk of international spread</div>\n        <div style=\"font-size:12px;color:#0F172A;margin-top:2px;\">Evidence of cross-border transmission, infected travellers, contaminated conveyances, contacts crossing borders.</div>\n      </td>\n    </tr>\n    <tr>\n      <td style=\"padding:10px 14px;\">\n        <div style=\"font-size:11px;text-transform:uppercase;letter-spacing:0.06em;color:#6D28D9;font-weight:700;\">4 · Significant risk of international travel / trade restrictions</div>\n        <div style=\"font-size:12px;color:#0F172A;margin-top:2px;\">Event likely to prompt other states to restrict movement / trade / conveyances.</div>\n      </td>\n    </tr>\n  </table>\n  <p style=\"margin:8px 0 0;font-size:11px;color:#5B21B6;\"><strong>Rule of thumb:</strong> if any 2 of the 4 criteria apply → WHO notification is mandatory within 24 hours.</p>\n</td></tr>\n\n<tr><td style=\"padding:16px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#5B21B6;font-weight:800;\">Event context</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;border:1px solid #E2E8F0;border-radius:6px;background:#F8FAFC;\">\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Alert · country · POE</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;font-weight:700;\">{{alert_code}} · {{country_name}} · {{poe_code}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Suspected disease</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{disease_name}} · {{disease_who_category}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">CFR</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{disease_cfr_pct}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Traveller</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{traveler_name}} · {{traveler_age}} · {{traveler_nationality}} → {{country_name}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Travel path</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{journey_start}} → {{embarkation_port}} → {{poe_code}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Conveyance · seat</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{conveyance_type}} {{conveyance_id}} · seat {{seat_number}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Detected</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{captured_at}} · {{captured_by_name}}</td></tr>\n  </table>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#5B21B6;font-weight:800;\">Cross-border spread signal</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F5F3FF;border:1px solid #DDD6FE;border-radius:8px;\">\n    <div style=\"font-size:12px;color:#0F172A;\">Travel history on file:</div>\n    <div style=\"margin-top:6px;\">{{{travel_html}}}</div>\n    <p style=\"margin:10px 0 0;font-size:12px;color:#5B21B6;\"><em>Every country listed must be considered for cross-border notification to their IHR NFP if the case is confirmed.</em></p>\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#5B21B6;font-weight:800;\">Clinical evidence</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:8px;\">\n    <p style=\"margin:0 0 6px;font-size:12px;\"><strong>Syndrome:</strong> {{syndrome_classification}} · <strong>triage:</strong> {{triage_category}} · <strong>ER signs:</strong> {{emergency_signs}}</p>\n    {{{symptoms_html}}}\n    <hr style=\"border:none;border-top:1px dashed #E2E8F0;margin:10px 0;\">\n    {{{exposures_html}}}\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">{{{disease_intel_html}}}</td></tr>\n\n<tr><td style=\"padding:0 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#5B21B6;font-weight:800;\">Expected actions — NATIONAL IHR NFP</div>\n  <ol style=\"margin:10px 0 0 20px;padding:0;font-size:13px;color:#0F172A;\">\n    <li style=\"margin:6px 0;\">Complete Annex 2 decision instrument within <strong>48 hours</strong>.</li>\n    <li style=\"margin:6px 0;\">Coordinate multi-sectoral risk assessment (MoH + IHR NFP + PHEOC).</li>\n    <li style=\"margin:6px 0;\">If 2+ criteria confirmed → submit IHR notification to WHO within <strong>24 hours</strong>.</li>\n    <li style=\"margin:6px 0;\">Pre-warn neighbouring country IHR NFPs if cross-border spread plausible.</li>\n    <li style=\"margin:6px 0;\">Initiate appropriate border-health measures (screening, tracing, quarantine).</li>\n    <li style=\"margin:6px 0;\">Prepare public risk communication with WHO country office.</li>\n  </ol>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#5B21B6;font-weight:800;\">Current follow-up obligations ({{followups_count}})</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:6px;\">{{{followups_html}}}</div>\n</td></tr>\n\n<tr><td style=\"padding:20px 28px 14px;\">\n  <div style=\"background:#5B21B6;border-radius:8px;padding:14px 16px;text-align:center;\">\n    <a href=\"{{console_url}}\" style=\"color:#FFFFFF;font-size:14px;font-weight:700;text-decoration:none;\">Complete Annex 2 assessment →</a>\n  </div>\n</td></tr>\n<tr><td style=\"padding:18px 28px 12px;background:#F1F5F9;border-top:1px solid #E2E8F0;\">\n  <p style=\"margin:0;font-size:11px;color:#475569;line-height:1.5;\">\n    <strong>{{country_name}} POE Sentinel</strong> · IHR ANNEX 2 ASSESSMENT · WHO IHR 2005 &amp; AFRO IDSR 3rd Ed. aligned.<br>\n    Alert <strong>{{alert_code}}</strong> · {{risk_level_label}} · fired {{alert_created_ago}} at {{alert_created_at}}.<br>\n    Open in console → <a href=\"{{console_url}}\" style=\"color:#1D4ED8;text-decoration:none;font-weight:600;\">{{console_url}}</a>\n  </p>\n</td></tr>\n<tr><td style=\"padding:8px 28px 18px;background:#F1F5F9;\">\n  <p style=\"margin:0;font-size:10px;color:#64748B;line-height:1.4;\">\n    This is a transactional public-health alert generated by the national surveillance pipeline. Do not reply; coordinate through the escalation ladder.<br>\n    Generated {{now}} UTC · template {{alert_code}} · recipient action expected within {{ack_sla_hours}}h.\n  </p>\n</td></tr></table></td></tr></table></body></html>', 'POE SENTINEL — IHR ANNEX 2 DECISION INSTRUMENT\nAlert {{alert_code}} · {{country_name}} · POE {{poe_code}}\n\nAt least one of the four Annex 2 criteria has fired. National risk assessment required.\nIf 2+ criteria → WHO notification mandatory within 24h.\n\nCRITERIA (rule: 2 of 4 → notify):\n 1. Serious public-health impact\n 2. Unusual or unexpected event\n 3. Significant risk of international spread\n 4. Significant risk of travel/trade restrictions\n\nEVENT:\n · Disease: {{disease_name}} ({{disease_who_category}})\n · CFR: {{disease_cfr_pct}}\n · Traveller: {{traveler_name}} · {{traveler_age}} · {{traveler_nationality}}\n · Path: {{journey_start}} → {{embarkation_port}} → {{poe_code}}\n · Conveyance: {{conveyance_type}} {{conveyance_id}} seat {{seat_number}}\n · Detected: {{captured_at}} by {{captured_by_name}}\n · Syndrome: {{syndrome_classification}} · triage {{triage_category}} · ER signs {{emergency_signs}}\n\nIHR notification window: {{disease_ihr_notification}}\nTransmission: {{disease_transmission}}\nDifferential: {{disease_differential}}\n\nOpen Annex 2 workflow → {{console_url}}', '[\"PHEOC\", \"NATIONAL\", \"WHO\"]', 0, 1, '2026-04-21 18:15:56', '2026-04-21 18:15:56'),
(5, 'BREACH_717', 'EMAIL', '⏱ 7-1-7 BREACH · {{alert_code}} · {{poe_code}} · root-cause due 24h', '<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"></head><body style=\"margin:0;padding:0;background:#EEF2F7;font-family:Arial,Helvetica,sans-serif;color:#0F172A;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#EEF2F7;padding:24px 12px;\"><tr><td align=\"center\"><table role=\"presentation\" width=\"640\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:640px;background:#FFFFFF;border-radius:10px;overflow:hidden;box-shadow:0 4px 16px rgba(15,23,42,0.08);\"><tr><td style=\"background:linear-gradient(135deg,#000000 0%,#7F1D1D 60%,#991B1B 100%);padding:26px 28px;\">\n  <div style=\"font-size:11px;letter-spacing:0.22em;text-transform:uppercase;color:#FECACA;font-weight:700;\">7 · 1 · 7 FRAMEWORK BREACH</div>\n  <div style=\"margin-top:6px;font-size:12px;color:#FCA5A5;font-weight:600;\">Response stage missed — root-cause review required immediately.</div>\n  <div style=\"margin-top:12px;font-size:24px;font-weight:800;color:#FFFFFF;line-height:1.15;\">⏱ {{alert_code}} breached the 7-1-7 clock</div>\n  <div style=\"margin-top:8px;font-size:13px;color:#FECACA;\">{{alert_title}}</div>\n</td></tr>\n\n<tr><td style=\"padding:22px 28px 0;\">\n  <p style=\"margin:0;font-size:13px;color:#0F172A;\">The global 7-1-7 target for outbreak response (<strong>7 days</strong> to detect, <strong>1 day</strong> to notify, <strong>7 days</strong> for effective early response) has been missed on this alert. This email is the breach notification for the record. A <strong>bottleneck review + root-cause analysis</strong> must be completed and attached to the alert in the console within 24 hours.</p>\n</td></tr>\n\n<tr><td style=\"padding:16px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#7F1D1D;font-weight:800;\">Timeline · where did time go?</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;background:#FEE2E2;border:1px solid #FCA5A5;border-radius:8px;\">\n    <tr><td style=\"padding:8px 12px;border-bottom:1px solid #FCA5A5;font-size:12px;color:#7F1D1D;font-weight:700;\">DETECT · target ≤7 days from first signal</td><td style=\"padding:8px 12px;border-bottom:1px solid #FCA5A5;font-size:12px;text-align:right;\">first signal {{captured_at}}</td></tr>\n    <tr><td style=\"padding:8px 12px;border-bottom:1px solid #FCA5A5;font-size:12px;color:#7F1D1D;font-weight:700;\">NOTIFY · target ≤1 day from detection</td><td style=\"padding:8px 12px;border-bottom:1px solid #FCA5A5;font-size:12px;text-align:right;\">alert raised {{alert_created_at}}</td></tr>\n    <tr><td style=\"padding:8px 12px;border-bottom:1px solid #FCA5A5;font-size:12px;color:#7F1D1D;font-weight:700;\">RESPOND · target effective response ≤7 days</td><td style=\"padding:8px 12px;border-bottom:1px solid #FCA5A5;font-size:12px;text-align:right;\">{{followups_overdue_count}} follow-ups overdue of {{followups_count}}</td></tr>\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#7F1D1D;font-weight:700;\">Acknowledgement state</td><td style=\"padding:8px 12px;font-size:12px;text-align:right;\">by {{acknowledged_by_name}} at {{alert_acknowledged_at}}</td></tr>\n  </table>\n</td></tr>\n\n<tr><td style=\"padding:16px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#7F1D1D;font-weight:800;\">Root-cause questions · answer in the console</div>\n  <ol style=\"margin:8px 0 0 20px;padding:0;font-size:13px;color:#0F172A;\">\n    <li style=\"margin:6px 0;\">Was the <strong>primary signal</strong> recognised on time? What delayed detection?</li>\n    <li style=\"margin:6px 0;\">What caused the <strong>notification gap</strong> between first symptom and alert creation?</li>\n    <li style=\"margin:6px 0;\">Which <strong>follow-up actions</strong> are lagging? Who owns them?</li>\n    <li style=\"margin:6px 0;\">Are there <strong>resource constraints</strong> (PPE, transport, lab turnaround, staff)?</li>\n    <li style=\"margin:6px 0;\">What is the <strong>mitigation plan</strong> so this POE does not breach the next alert?</li>\n  </ol>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#7F1D1D;font-weight:800;\">Case context</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;border:1px solid #E2E8F0;border-radius:6px;background:#F8FAFC;\">\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Disease · risk</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;font-weight:700;\">{{disease_name}} · {{risk_level_label}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Country · POE · district</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{country_name}} · {{poe_code}} · {{district_code}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Traveller</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{traveler_name}} · {{traveler_age}} · {{traveler_nationality}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Routed to</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{routed_to_level}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Ladder</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{escalation_ladder}}</td></tr>\n  </table>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#7F1D1D;font-weight:800;\">Follow-ups that need owners NOW</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#FEF2F2;border:1px solid #FCA5A5;border-radius:6px;\">{{{followups_html}}}</div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#7F1D1D;font-weight:800;\">Prior alerts at {{poe_code}}</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:6px;\">{{{prior_alerts_html}}}</div>\n</td></tr>\n\n<tr><td style=\"padding:20px 28px 14px;\">\n  <div style=\"background:#991B1B;border-radius:8px;padding:14px 16px;text-align:center;\">\n    <a href=\"{{console_url}}\" style=\"color:#FFFFFF;font-size:14px;font-weight:700;text-decoration:none;\">Log 7-1-7 root-cause for {{alert_code}} →</a>\n  </div>\n</td></tr>\n<tr><td style=\"padding:18px 28px 12px;background:#F1F5F9;border-top:1px solid #E2E8F0;\">\n  <p style=\"margin:0;font-size:11px;color:#475569;line-height:1.5;\">\n    <strong>{{country_name}} POE Sentinel</strong> · 7-1-7 BREACH NOTICE · WHO IHR 2005 &amp; AFRO IDSR 3rd Ed. aligned.<br>\n    Alert <strong>{{alert_code}}</strong> · {{risk_level_label}} · fired {{alert_created_ago}} at {{alert_created_at}}.<br>\n    Open in console → <a href=\"{{console_url}}\" style=\"color:#1D4ED8;text-decoration:none;font-weight:600;\">{{console_url}}</a>\n  </p>\n</td></tr>\n<tr><td style=\"padding:8px 28px 18px;background:#F1F5F9;\">\n  <p style=\"margin:0;font-size:10px;color:#64748B;line-height:1.4;\">\n    This is a transactional public-health alert generated by the national surveillance pipeline. Do not reply; coordinate through the escalation ladder.<br>\n    Generated {{now}} UTC · template {{alert_code}} · recipient action expected within {{ack_sla_hours}}h.\n  </p>\n</td></tr></table></td></tr></table></body></html>', '7-1-7 BREACH — {{alert_code}}\n{{country_name}} · POE {{poe_code}} · disease {{disease_name}} · risk {{risk_level_label}}\n\nThe 7-1-7 target (detect ≤7d · notify ≤1d · respond ≤7d) has been missed.\nA root-cause review must be filed in the console within 24h.\n\nTIMELINE\n · Detect: first signal {{captured_at}}\n · Notify: alert raised {{alert_created_at}}\n · Respond: {{followups_overdue_count}} of {{followups_count}} follow-ups overdue\n · Acknowledged by: {{acknowledged_by_name}} at {{alert_acknowledged_at}}\n\nROOT-CAUSE QUESTIONS\n 1. Why was the signal delayed?\n 2. Why was alert creation delayed?\n 3. Which follow-ups are stuck?\n 4. Resource constraints?\n 5. Mitigation plan?\n\nOpen in console → {{console_url}}', '[\"PHEOC\", \"NATIONAL\"]', 0, 1, '2026-04-21 18:15:56', '2026-04-21 18:15:56'),
(6, 'FOLLOWUP_DUE', 'EMAIL', '◷ Due · {{followup_action_code}} · {{alert_code}} · {{poe_code}} · by {{followup_due_at}}', '<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"></head><body style=\"margin:0;padding:0;background:#EEF2F7;font-family:Arial,Helvetica,sans-serif;color:#0F172A;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#EEF2F7;padding:24px 12px;\"><tr><td align=\"center\"><table role=\"presentation\" width=\"640\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:640px;background:#FFFFFF;border-radius:10px;overflow:hidden;box-shadow:0 4px 16px rgba(15,23,42,0.08);\"><tr><td style=\"background:linear-gradient(135deg,#0C4A6E 0%,#075985 50%,#0EA5E9 100%);padding:24px 28px;\">\n  <div style=\"font-size:11px;letter-spacing:0.18em;text-transform:uppercase;color:#BAE6FD;font-weight:700;\">RTSL 14 · EARLY RESPONSE ACTION DUE</div>\n  <div style=\"margin-top:6px;font-size:12px;color:#E0F2FE;\">Scheduled follow-up for alert {{alert_code}} — action window open now.</div>\n  <div style=\"margin-top:12px;font-size:22px;font-weight:800;color:#FFFFFF;line-height:1.2;\">◷ {{followup_action_label}}</div>\n  <div style=\"margin-top:8px;font-size:13px;color:#BAE6FD;\">Owner: {{followup_assignee}} · Due: {{followup_due_at}}</div>\n</td></tr>\n\n<tr><td style=\"padding:22px 28px 0;\">\n  <p style=\"margin:0;font-size:13px;color:#0F172A;\">This is a scheduled Resolve-to-Save-Lives 14 early-response action tied to alert <strong>{{alert_code}}</strong>. You have been assigned as the action owner. Close the loop in the console — mark completed, blocked, or not-applicable with evidence.</p>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#075985;font-weight:800;\">Action brief</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;background:#F0F9FF;border:1px solid #BAE6FD;border-radius:6px;\">\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#0C4A6E;\">Action code</td><td style=\"padding:8px 12px;font-size:12px;text-align:right;font-weight:700;\">{{followup_action_code}}</td></tr>\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#0C4A6E;vertical-align:top;\">Action</td><td style=\"padding:8px 12px;font-size:12px;text-align:right;\">{{followup_action_label}}</td></tr>\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#0C4A6E;\">Status</td><td style=\"padding:8px 12px;font-size:12px;text-align:right;font-weight:700;\">{{followup_status}}</td></tr>\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#0C4A6E;\">Due</td><td style=\"padding:8px 12px;font-size:12px;text-align:right;font-weight:700;color:#0369A1;\">{{followup_due_at}}</td></tr>\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#0C4A6E;\">Blocks alert closure?</td><td style=\"padding:8px 12px;font-size:12px;text-align:right;\">{{followup_blocks_closure}}</td></tr>\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#0C4A6E;\">Current notes</td><td style=\"padding:8px 12px;font-size:12px;text-align:right;\"><em>{{followup_notes}}</em></td></tr>\n  </table>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#075985;font-weight:800;\">Why this action matters</div>\n  <p style=\"margin:6px 0 0;font-size:13px;color:#0F172A;\">This is one of {{followups_count}} RTSL-14 actions seeded at alert creation. Completing on time is how the country meets the global <strong>7-1-7 response target</strong>. {{followups_overdue_count}} action(s) on this alert are already overdue.</p>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#075985;font-weight:800;\">Alert context</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;border:1px solid #E2E8F0;border-radius:6px;background:#F8FAFC;\">\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Alert · risk</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;font-weight:700;\">{{alert_code}} · {{risk_level_label}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Disease</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{disease_name}} · {{disease_who_category}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Country · POE · district</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{country_name}} · {{poe_code}} · {{district_code}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Traveller</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{traveler_name}} · {{traveler_age}} · {{traveler_nationality}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Disposition</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{final_disposition}}</td></tr>\n  </table>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#075985;font-weight:800;\">Evidence to attach when you complete</div>\n  <ul style=\"margin:8px 0 0 20px;padding:0;font-size:13px;color:#0F172A;\">\n    <li style=\"margin:4px 0;\">Document / photo showing the action was performed</li>\n    <li style=\"margin:4px 0;\">Name of team member who carried it out</li>\n    <li style=\"margin:4px 0;\">Completion time (UTC or local with TZ)</li>\n    <li style=\"margin:4px 0;\">Any deviation from SOP and the reason</li>\n  </ul>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#075985;font-weight:800;\">All follow-ups on this alert</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F0F9FF;border:1px solid #BAE6FD;border-radius:6px;\">{{{followups_html}}}</div>\n</td></tr>\n\n<tr><td style=\"padding:20px 28px 14px;\">\n  <div style=\"background:#075985;border-radius:8px;padding:14px 16px;text-align:center;\">\n    <a href=\"{{console_url}}\" style=\"color:#FFFFFF;font-size:14px;font-weight:700;text-decoration:none;\">Mark {{followup_action_code}} complete →</a>\n  </div>\n</td></tr>\n<tr><td style=\"padding:18px 28px 12px;background:#F1F5F9;border-top:1px solid #E2E8F0;\">\n  <p style=\"margin:0;font-size:11px;color:#475569;line-height:1.5;\">\n    <strong>{{country_name}} POE Sentinel</strong> · FOLLOW-UP DUE · RTSL 14 early-response framework + WHO AFRO IDSR 2021.<br>\n    Alert <strong>{{alert_code}}</strong> · fired {{alert_created_ago}} at {{alert_created_at}}.<br>\n    Open in console → <a href=\"{{console_url}}\" style=\"color:#1D4ED8;text-decoration:none;font-weight:600;\">{{console_url}}</a>\n  </p>\n</td></tr></table></td></tr></table></body></html>', 'RTSL 14 · FOLLOW-UP DUE\nAlert {{alert_code}} · action {{followup_action_code}}\n{{followup_action_label}}\n\nOwner: {{followup_assignee}}\nDue: {{followup_due_at}}\nStatus: {{followup_status}}\nBlocks closure: {{followup_blocks_closure}}\nNotes: {{followup_notes}}\n\nContext:\n · Disease {{disease_name}} · risk {{risk_level_label}}\n · {{country_name}} · POE {{poe_code}} · {{district_code}}\n · Traveller {{traveler_name}} · {{traveler_age}} · {{traveler_nationality}}\n · Disposition {{final_disposition}}\n\n{{followups_overdue_count}} of {{followups_count}} follow-ups on this alert are already overdue.\nComplete in console with evidence → {{console_url}}', '[\"POE\", \"DISTRICT\", \"PHEOC\"]', 0, 1, '2026-04-21 18:15:56', '2026-04-21 18:15:56'),
(7, 'FOLLOWUP_OVERDUE', 'EMAIL', '⊘ OVERDUE {{followup_overdue_hours}}h · {{followup_action_code}} · {{alert_code}}', '<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"></head><body style=\"margin:0;padding:0;background:#EEF2F7;font-family:Arial,Helvetica,sans-serif;color:#0F172A;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#EEF2F7;padding:24px 12px;\"><tr><td align=\"center\"><table role=\"presentation\" width=\"640\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:640px;background:#FFFFFF;border-radius:10px;overflow:hidden;box-shadow:0 4px 16px rgba(15,23,42,0.08);\"><tr><td style=\"background:linear-gradient(135deg,#7F1D1D 0%,#B91C1C 50%,#DB2777 100%);padding:24px 28px;\">\n  <div style=\"font-size:11px;letter-spacing:0.18em;text-transform:uppercase;color:#FBCFE8;font-weight:700;\">OVERDUE · RTSL 14 action past its window</div>\n  <div style=\"margin-top:6px;font-size:12px;color:#FCE7F3;\">This is the escalation notice — supervisor copy appended.</div>\n  <div style=\"margin-top:12px;font-size:22px;font-weight:800;color:#FFFFFF;line-height:1.2;\">⊘ OVERDUE · {{followup_action_label}}</div>\n  <div style=\"margin-top:8px;font-size:13px;color:#FBCFE8;\">Overdue by {{followup_overdue_hours}} h ({{followup_overdue_minutes}} min) · was due {{followup_due_at}}</div>\n</td></tr>\n\n<tr><td style=\"padding:22px 28px 0;\">\n  <p style=\"margin:0;font-size:13px;color:#0F172A;\">An RTSL-14 early response action tied to <strong>{{alert_code}}</strong> is now <strong>overdue</strong>. The alert is exposed to the 7-1-7 breach clock; the supervisor copy is visible on this thread. Please take direct action now.</p>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#B91C1C;font-weight:800;\">Overdue action</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;background:#FFF1F2;border:1px solid #FECDD3;border-radius:6px;\">\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#7F1D1D;\">Code</td><td style=\"padding:8px 12px;font-size:12px;text-align:right;font-weight:700;\">{{followup_action_code}}</td></tr>\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#7F1D1D;vertical-align:top;\">Label</td><td style=\"padding:8px 12px;font-size:12px;text-align:right;\">{{followup_action_label}}</td></tr>\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#7F1D1D;\">Current status</td><td style=\"padding:8px 12px;font-size:12px;text-align:right;font-weight:700;\">{{followup_status}}</td></tr>\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#7F1D1D;\">Was due</td><td style=\"padding:8px 12px;font-size:12px;text-align:right;\">{{followup_due_at}}</td></tr>\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#7F1D1D;\">Overdue by</td><td style=\"padding:8px 12px;font-size:12px;text-align:right;font-weight:700;color:#B91C1C;\">{{followup_overdue_hours}} h</td></tr>\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#7F1D1D;\">Assigned to</td><td style=\"padding:8px 12px;font-size:12px;text-align:right;\">{{followup_assignee}}</td></tr>\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#7F1D1D;\">Blocks alert closure?</td><td style=\"padding:8px 12px;font-size:12px;text-align:right;font-weight:700;\">{{followup_blocks_closure}}</td></tr>\n  </table>\n</td></tr>\n\n<tr><td style=\"padding:16px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#B91C1C;font-weight:800;\">What happens if this stays overdue</div>\n  <ul style=\"margin:8px 0 0 20px;padding:0;font-size:13px;color:#0F172A;\">\n    <li style=\"margin:4px 0;\">7-1-7 response window is being eaten — this <em>will</em> cause a BREACH_717 notice.</li>\n    <li style=\"margin:4px 0;\">If <strong>blocks_closure = YES</strong> the parent alert cannot be closed until this is resolved.</li>\n    <li style=\"margin:4px 0;\">On next digest the alert is flagged on the national intelligence brief.</li>\n    <li style=\"margin:4px 0;\">Supervisor level ({{routed_to_level}}) is now receiving these notices until resolution.</li>\n  </ul>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#B91C1C;font-weight:800;\">Case in which this action sits</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;border:1px solid #E2E8F0;border-radius:6px;background:#F8FAFC;\">\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Alert · risk</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;font-weight:700;\">{{alert_code}} · {{risk_level_label}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Disease</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{disease_name}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Country · POE · district</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{country_name}} · {{poe_code}} · {{district_code}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Disposition</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{final_disposition}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Officer notes</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\"><em>{{officer_notes}}</em></td></tr>\n  </table>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#B91C1C;font-weight:800;\">Other follow-ups ({{followups_count}} · {{followups_overdue_count}} overdue)</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#FFF1F2;border:1px solid #FECDD3;border-radius:6px;\">{{{followups_html}}}</div>\n</td></tr>\n\n<tr><td style=\"padding:20px 28px 14px;\">\n  <div style=\"background:#B91C1C;border-radius:8px;padding:14px 16px;text-align:center;\">\n    <a href=\"{{console_url}}\" style=\"color:#FFFFFF;font-size:14px;font-weight:700;text-decoration:none;\">Resolve {{followup_action_code}} now →</a>\n  </div>\n</td></tr>\n<tr><td style=\"padding:18px 28px 12px;background:#F1F5F9;border-top:1px solid #E2E8F0;\">\n  <p style=\"margin:0;font-size:11px;color:#475569;line-height:1.5;\">\n    <strong>{{country_name}} POE Sentinel</strong> · OVERDUE · ESCALATED · RTSL 14 early-response framework + WHO AFRO IDSR 2021.<br>\n    Alert <strong>{{alert_code}}</strong> · fired {{alert_created_ago}} at {{alert_created_at}}.<br>\n    Open in console → <a href=\"{{console_url}}\" style=\"color:#1D4ED8;text-decoration:none;font-weight:600;\">{{console_url}}</a>\n  </p>\n</td></tr></table></td></tr></table></body></html>', 'OVERDUE — RTSL 14 early response action\nAlert {{alert_code}} · action {{followup_action_code}}\n{{followup_action_label}}\n\nWas due: {{followup_due_at}}\nOverdue by: {{followup_overdue_hours}} h ({{followup_overdue_minutes}} min)\nOwner: {{followup_assignee}}\nStatus: {{followup_status}}\nBlocks closure: {{followup_blocks_closure}}\n\nIMPACT\n · 7-1-7 breach clock is ticking on this alert.\n · If blocks_closure = YES the parent alert cannot close.\n · Supervisor level {{routed_to_level}} is now receiving copies.\n\nContext: {{disease_name}} · {{country_name}} · POE {{poe_code}} · disposition {{final_disposition}}\nAll follow-ups: {{followups_count}} seeded · {{followups_overdue_count}} overdue.\n\nResolve now → {{console_url}}', '[\"POE\", \"DISTRICT\", \"PHEOC\", \"NATIONAL\"]', 0, 1, '2026-04-21 18:15:56', '2026-04-21 18:15:56'),
(8, 'DAILY_REPORT', 'EMAIL', '▤ Daily digest · {{country_name}} · {{alerts_24h}} alerts · {{followups_overdue_total}} overdue', '<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"></head><body style=\"margin:0;padding:0;background:#EEF2F7;font-family:Arial,Helvetica,sans-serif;color:#0F172A;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#EEF2F7;padding:24px 12px;\"><tr><td align=\"center\"><table role=\"presentation\" width=\"640\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:640px;background:#FFFFFF;border-radius:10px;overflow:hidden;box-shadow:0 4px 16px rgba(15,23,42,0.08);\"><tr><td style=\"background:linear-gradient(135deg,#334155 0%,#475569 50%,#64748B 100%);padding:24px 28px;\">\n  <div style=\"font-size:11px;letter-spacing:0.22em;text-transform:uppercase;color:#CBD5E1;font-weight:700;\">{{country_name}} POE SENTINEL · DAILY DIGEST</div>\n  <div style=\"margin-top:6px;font-size:12px;color:#E2E8F0;\">Window: last 24 hours · issued {{now}}</div>\n  <div style=\"margin-top:12px;font-size:22px;font-weight:800;color:#FFFFFF;line-height:1.2;\">▤ National POE activity · 24h</div>\n</td></tr>\n\n<tr><td style=\"padding:22px 28px 0;\">\n  <p style=\"margin:0;font-size:13px;color:#0F172A;\">This digest gives you a decision-grade briefing on national POE surveillance activity over the past 24 hours. Every section links back to the console for deep dive.</p>\n</td></tr>\n\n<tr><td style=\"padding:16px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#334155;font-weight:800;\">Top-line KPIs</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;\">\n    <tr>\n      <td style=\"padding:4px;width:33%;\">\n        <div style=\"padding:14px;background:#F1F5F9;border-radius:8px;border-left:4px solid #0EA5E9;\">\n          <div style=\"font-size:10px;text-transform:uppercase;color:#475569;letter-spacing:0.06em;\">Primary screenings</div>\n          <div style=\"font-size:22px;font-weight:800;color:#0F172A;margin-top:4px;\">{{primary_screenings_24h}}</div>\n          <div style=\"font-size:11px;color:#64748B;margin-top:2px;\">{{primary_symptomatic_24h}} symptomatic</div>\n        </div>\n      </td>\n      <td style=\"padding:4px;width:33%;\">\n        <div style=\"padding:14px;background:#F1F5F9;border-radius:8px;border-left:4px solid #B45309;\">\n          <div style=\"font-size:10px;text-transform:uppercase;color:#475569;letter-spacing:0.06em;\">Alerts raised</div>\n          <div style=\"font-size:22px;font-weight:800;color:#0F172A;margin-top:4px;\">{{alerts_24h}}</div>\n          <div style=\"font-size:11px;color:#64748B;margin-top:2px;\">{{alerts_critical_24h}} CRITICAL · {{alerts_high_24h}} HIGH</div>\n        </div>\n      </td>\n      <td style=\"padding:4px;width:33%;\">\n        <div style=\"padding:14px;background:#F1F5F9;border-radius:8px;border-left:4px solid #B91C1C;\">\n          <div style=\"font-size:10px;text-transform:uppercase;color:#475569;letter-spacing:0.06em;\">Overdue follow-ups</div>\n          <div style=\"font-size:22px;font-weight:800;color:#B91C1C;margin-top:4px;\">{{followups_overdue_total}}</div>\n          <div style=\"font-size:11px;color:#64748B;margin-top:2px;\">{{followups_due_today}} due today</div>\n        </div>\n      </td>\n    </tr>\n  </table>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#334155;font-weight:800;\">Alerts by risk</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;border:1px solid #E2E8F0;border-radius:6px;background:#F8FAFC;\">\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">CRITICAL</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;font-weight:700;color:#B91C1C;\">{{alerts_critical_24h}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">HIGH</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;font-weight:700;color:#B45309;\">{{alerts_high_24h}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">MEDIUM</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{alerts_medium_24h}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">LOW</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{alerts_low_24h}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Open &gt; 24h (not yet acknowledged)</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;font-weight:700;color:#B91C1C;\">{{alerts_stuck_open}}</td></tr>\n  </table>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#334155;font-weight:800;\">POE activity (top + silent)</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:6px;\">\n    <p style=\"margin:0 0 6px;font-size:12px;color:#475569;\"><strong>Top 5 POEs by activity</strong></p>\n    {{{top_poes_html}}}\n    <hr style=\"border:none;border-top:1px dashed #E2E8F0;margin:10px 0;\">\n    <p style=\"margin:0 0 6px;font-size:12px;color:#B91C1C;font-weight:700;\">Silent POEs (&gt;24h without a submission)</p>\n    {{{silent_poes_html}}}\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#334155;font-weight:800;\">Syndromes seen in the window</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:6px;\">{{{syndromes_html}}}</div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#334155;font-weight:800;\">Dispositions</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;border:1px solid #E2E8F0;border-radius:6px;background:#F8FAFC;\">\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Released</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{disposition_released}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Referred</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{disposition_referred}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Isolated / Quarantined</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{disposition_isolated}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Denied boarding / Delayed</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{disposition_delayed}}</td></tr>\n  </table>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#334155;font-weight:800;\">What to do today</div>\n  <ul style=\"margin:8px 0 0 20px;padding:0;font-size:13px;color:#0F172A;\">\n    <li style=\"margin:4px 0;\">Acknowledge any CRITICAL / HIGH alert still open after 24h.</li>\n    <li style=\"margin:4px 0;\">Clear {{followups_overdue_total}} overdue RTSL-14 follow-ups — each one ticks the 7-1-7 clock.</li>\n    <li style=\"margin:4px 0;\">Reach out to silent POEs listed above to confirm duty roster + network.</li>\n    <li style=\"margin:4px 0;\">Review top-ranked suspected diseases for cluster patterns.</li>\n  </ul>\n</td></tr>\n\n<tr><td style=\"padding:20px 28px 14px;\">\n  <div style=\"background:#334155;border-radius:8px;padding:14px 16px;text-align:center;\">\n    <a href=\"{{console_url}}\" style=\"color:#FFFFFF;font-size:14px;font-weight:700;text-decoration:none;\">Open national dashboard →</a>\n  </div>\n</td></tr>\n<tr><td style=\"padding:18px 28px 14px;background:#F1F5F9;border-top:1px solid #E2E8F0;\">\n  <p style=\"margin:0;font-size:11px;color:#475569;line-height:1.5;\">\n    <strong>{{country_name}} POE Sentinel</strong> · DAILY DIGEST · 24h · WHO IHR 2005 + AFRO IDSR 2021 + 7-1-7 framework.<br>\n    Digest generated {{now}} for window ending {{now_date}}.<br>\n    Open dashboard → <a href=\"{{console_url}}\" style=\"color:#1D4ED8;text-decoration:none;font-weight:600;\">{{console_url}}</a>\n  </p>\n</td></tr></table></td></tr></table></body></html>', '{{country_name}} POE SENTINEL — DAILY DIGEST (last 24h)\nIssued {{now}}\n\nTOP-LINE\n · Primary screenings: {{primary_screenings_24h}} ({{primary_symptomatic_24h}} symptomatic)\n · Alerts raised: {{alerts_24h}} ({{alerts_critical_24h}} CRITICAL · {{alerts_high_24h}} HIGH · {{alerts_medium_24h}} MEDIUM · {{alerts_low_24h}} LOW)\n · Alerts open >24h: {{alerts_stuck_open}}\n · Follow-ups overdue: {{followups_overdue_total}}\n · Follow-ups due today: {{followups_due_today}}\n\nDispositions:\n · Released {{disposition_released}} · Referred {{disposition_referred}}\n · Isolated/Quarantined {{disposition_isolated}} · Delayed/Denied {{disposition_delayed}}\n\nTODAY\n · Acknowledge CRITICAL/HIGH alerts still open after 24h\n · Clear {{followups_overdue_total}} overdue follow-ups\n · Contact silent POEs\n · Review suspected disease ranking for clusters\n\nOpen dashboard → {{console_url}}', '[\"PHEOC\", \"NATIONAL\"]', 0, 1, '2026-04-21 18:15:56', '2026-04-21 18:15:56');
INSERT INTO `notification_templates` (`id`, `template_code`, `channel`, `subject_template`, `body_html_template`, `body_text_template`, `applicable_levels`, `is_ai_enhanced`, `is_active`, `created_at`, `updated_at`) VALUES
(9, 'WEEKLY_REPORT', 'EMAIL', '▥ Weekly scorecard · {{country_name}} · {{alerts_high_plus_7d}} alerts · {{respond_compliance}}% 7-1-7 respond', '<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"></head><body style=\"margin:0;padding:0;background:#EEF2F7;font-family:Arial,Helvetica,sans-serif;color:#0F172A;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#EEF2F7;padding:24px 12px;\"><tr><td align=\"center\"><table role=\"presentation\" width=\"640\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:640px;background:#FFFFFF;border-radius:10px;overflow:hidden;box-shadow:0 4px 16px rgba(15,23,42,0.08);\"><tr><td style=\"background:linear-gradient(135deg,#064E3B 0%,#047857 55%,#059669 100%);padding:26px 28px;\">\n  <div style=\"font-size:11px;letter-spacing:0.22em;text-transform:uppercase;color:#A7F3D0;font-weight:700;\">{{country_name}} POE SENTINEL · WEEKLY SCORECARD</div>\n  <div style=\"margin-top:6px;font-size:12px;color:#D1FAE5;\">7-day window · 7-1-7 performance + trend arrows vs. previous week.</div>\n  <div style=\"margin-top:12px;font-size:22px;font-weight:800;color:#FFFFFF;line-height:1.2;\">▥ Weekly executive briefing</div>\n</td></tr>\n\n<tr><td style=\"padding:22px 28px 0;\">\n  <p style=\"margin:0;font-size:13px;color:#0F172A;\">This is the executive summary of the past 7 days at all {{country_name}} Points of Entry — screening volume, alerts fired, 7-1-7 compliance, and outstanding actions that could cause breaches.</p>\n</td></tr>\n\n<tr><td style=\"padding:16px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#047857;font-weight:800;\">7-1-7 scorecard</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;background:#ECFDF5;border:1px solid #A7F3D0;border-radius:8px;\">\n    <tr><td style=\"padding:10px 14px;border-bottom:1px solid #A7F3D0;\">\n      <div style=\"font-size:12px;color:#047857;font-weight:700;\">Detect · within 7 days of first signal</div>\n      <div style=\"font-size:14px;color:#0F172A;margin-top:2px;\"><strong>{{detect_compliance}}%</strong> compliance · {{detect_breach_count}} breaches</div>\n    </td></tr>\n    <tr><td style=\"padding:10px 14px;border-bottom:1px solid #A7F3D0;\">\n      <div style=\"font-size:12px;color:#047857;font-weight:700;\">Notify · within 1 day of detection</div>\n      <div style=\"font-size:14px;color:#0F172A;margin-top:2px;\"><strong>{{notify_compliance}}%</strong> compliance · {{notify_breach_count}} breaches</div>\n    </td></tr>\n    <tr><td style=\"padding:10px 14px;\">\n      <div style=\"font-size:12px;color:#047857;font-weight:700;\">Respond · effective response within 7 days</div>\n      <div style=\"font-size:14px;color:#0F172A;margin-top:2px;\"><strong>{{respond_compliance}}%</strong> compliance · {{respond_breach_count}} breaches</div>\n    </td></tr>\n  </table>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#047857;font-weight:800;\">Volume &amp; trend</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;border:1px solid #E2E8F0;border-radius:6px;background:#F8FAFC;\">\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Primary screenings this week</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;font-weight:700;\">{{primary_screenings_7d}} ({{primary_trend}})</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Secondary screenings</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{secondary_screenings_7d}} ({{secondary_trend}})</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Alerts fired · CRITICAL + HIGH</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;font-weight:700;\">{{alerts_high_plus_7d}} ({{alerts_trend}})</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Follow-ups completed on time</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{followups_ontime_pct}}%</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Follow-ups overdue at report time</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;font-weight:700;color:#B91C1C;\">{{followups_overdue_total}}</td></tr>\n  </table>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#047857;font-weight:800;\">Disease spotlight — top syndromes + suspected diseases this week</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:6px;\">{{{top_diseases_html}}}</div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#047857;font-weight:800;\">POE leaderboard / lag list</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:6px;\">\n    <p style=\"margin:0 0 6px;font-size:12px;color:#047857;\"><strong>Top 5 POEs by on-time response</strong></p>\n    {{{top_poes_html}}}\n    <hr style=\"border:none;border-top:1px dashed #E2E8F0;margin:10px 0;\">\n    <p style=\"margin:0 0 6px;font-size:12px;color:#B91C1C;font-weight:700;\">Lag list — POEs with breaches or silence &gt;72h</p>\n    {{{lag_poes_html}}}\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#047857;font-weight:800;\">Executive actions for the coming week</div>\n  <ol style=\"margin:8px 0 0 20px;padding:0;font-size:13px;color:#0F172A;\">\n    <li style=\"margin:5px 0;\">Resolve all {{followups_overdue_total}} overdue follow-ups before next Monday.</li>\n    <li style=\"margin:5px 0;\">Intervene at lag-list POEs — deploy a supervisor visit or phone check-in.</li>\n    <li style=\"margin:5px 0;\">Review suspected-disease cluster patterns with epi team.</li>\n    <li style=\"margin:5px 0;\">Update national risk matrix if any Tier 1 advisories fired this week.</li>\n    <li style=\"margin:5px 0;\">Pre-brief the WHO country office on any Annex 2-positive events.</li>\n  </ol>\n</td></tr>\n\n<tr><td style=\"padding:20px 28px 14px;\">\n  <div style=\"background:#047857;border-radius:8px;padding:14px 16px;text-align:center;\">\n    <a href=\"{{console_url}}\" style=\"color:#FFFFFF;font-size:14px;font-weight:700;text-decoration:none;\">Open full weekly dashboard →</a>\n  </div>\n</td></tr>\n<tr><td style=\"padding:18px 28px 14px;background:#F1F5F9;border-top:1px solid #E2E8F0;\">\n  <p style=\"margin:0;font-size:11px;color:#475569;line-height:1.5;\">\n    <strong>{{country_name}} POE Sentinel</strong> · WEEKLY SCORECARD · 7d · WHO IHR 2005 + AFRO IDSR 2021 + 7-1-7 framework.<br>\n    Digest generated {{now}} for window ending {{now_date}}.<br>\n    Open dashboard → <a href=\"{{console_url}}\" style=\"color:#1D4ED8;text-decoration:none;font-weight:600;\">{{console_url}}</a>\n  </p>\n</td></tr></table></td></tr></table></body></html>', '{{country_name}} POE SENTINEL — WEEKLY EXECUTIVE BRIEF\nWindow: last 7 days · issued {{now}}\n\n7-1-7 SCORECARD\n · Detect ≤7d — {{detect_compliance}}% compliance · {{detect_breach_count}} breaches\n · Notify ≤1d — {{notify_compliance}}% compliance · {{notify_breach_count}} breaches\n · Respond ≤7d — {{respond_compliance}}% compliance · {{respond_breach_count}} breaches\n\nVOLUME\n · Primary screenings: {{primary_screenings_7d}} ({{primary_trend}})\n · Secondary screenings: {{secondary_screenings_7d}} ({{secondary_trend}})\n · CRITICAL+HIGH alerts: {{alerts_high_plus_7d}} ({{alerts_trend}})\n · Follow-ups on-time: {{followups_ontime_pct}}%\n · Follow-ups overdue: {{followups_overdue_total}}\n\nACTIONS THIS WEEK\n 1. Resolve {{followups_overdue_total}} overdue follow-ups\n 2. Intervene at lag-list POEs\n 3. Review suspected-disease clusters with epi team\n 4. Update national risk matrix if any Tier 1 fired\n 5. Brief WHO country office on Annex-2 positive events\n\nOpen weekly dashboard → {{console_url}}', '[\"PHEOC\", \"NATIONAL\"]', 0, 1, '2026-04-21 18:15:56', '2026-04-21 18:15:56'),
(10, 'ESCALATION', 'EMAIL', '▲ ESCALATION · {{alert_code}} · to {{routed_to_level}} · {{disease_name}}', '<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"></head><body style=\"margin:0;padding:0;background:#EEF2F7;font-family:Arial,Helvetica,sans-serif;color:#0F172A;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#EEF2F7;padding:24px 12px;\"><tr><td align=\"center\"><table role=\"presentation\" width=\"640\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:640px;background:#FFFFFF;border-radius:10px;overflow:hidden;box-shadow:0 4px 16px rgba(15,23,42,0.08);\"><tr><td style=\"background:linear-gradient(135deg,#881337 0%,#BE123C 55%,#E11D48 100%);padding:26px 28px;\">\n  <div style=\"font-size:11px;letter-spacing:0.22em;text-transform:uppercase;color:#FECDD3;font-weight:700;\">ESCALATION · next level of command</div>\n  <div style=\"margin-top:6px;font-size:12px;color:#FECDD3;font-weight:600;\">This alert could not be resolved at the previous level and is being escalated.</div>\n  <div style=\"margin-top:12px;font-size:22px;font-weight:800;color:#FFFFFF;line-height:1.15;\">▲ {{alert_code}} escalated to {{routed_to_level}}</div>\n  <div style=\"margin-top:8px;font-size:13px;color:#FECDD3;\">{{alert_title}}</div>\n</td></tr>\n\n<tr><td style=\"padding:22px 28px 0;\">\n  <p style=\"margin:0;font-size:13px;color:#0F172A;\">You are receiving this because {{alert_code}} requires decision-making capacity that does not sit at the POE or district level. Below is the rationale, the history so far, and the exact decisions expected of you.</p>\n</td></tr>\n\n<tr><td style=\"padding:16px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#BE123C;font-weight:800;\">Why this is being escalated</div>\n  <ul style=\"margin:8px 0 0 20px;padding:0;font-size:13px;color:#0F172A;\">\n    <li style=\"margin:4px 0;\">Risk classification: <strong>{{risk_level_label}}</strong>.</li>\n    <li style=\"margin:4px 0;\">Suspected disease: <strong>{{disease_name}}</strong> ({{disease_who_category}}) — CFR {{disease_cfr_pct}}.</li>\n    <li style=\"margin:4px 0;\">IHR notification window: {{disease_ihr_notification}}.</li>\n    <li style=\"margin:4px 0;\">{{followups_overdue_count}} of {{followups_count}} follow-up actions are already overdue.</li>\n    <li style=\"margin:4px 0;\">Escalation ladder in effect: {{escalation_ladder}}.</li>\n  </ul>\n</td></tr>\n\n<tr><td style=\"padding:16px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#BE123C;font-weight:800;\">Decisions expected of you</div>\n  <ol style=\"margin:8px 0 0 20px;padding:0;font-size:13px;color:#0F172A;\">\n    <li style=\"margin:5px 0;\">Acknowledge the alert in the console within <strong>{{ack_hours}} hours</strong> (by {{ack_deadline}}).</li>\n    <li style=\"margin:5px 0;\">Reassign owners for the {{followups_overdue_count}} overdue follow-ups.</li>\n    <li style=\"margin:5px 0;\">Authorise escalation to the next ladder level if appropriate.</li>\n    <li style=\"margin:5px 0;\">Confirm isolation posture per disease: {{disease_isolation}}.</li>\n    <li style=\"margin:5px 0;\">Coordinate with WHO country office if the Annex 2 criteria warrant notification.</li>\n  </ol>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#BE123C;font-weight:800;\">Snapshot of case</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;border:1px solid #E2E8F0;border-radius:6px;background:#F8FAFC;\">\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Traveller</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;font-weight:700;\">{{traveler_name}} · {{traveler_age}} · {{traveler_nationality}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">POE · district</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{poe_code}} · {{district_code}} · {{country_name}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Syndrome · triage</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{syndrome_classification}} · {{triage_category}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Disposition</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{final_disposition}} ({{disposition_details}})</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Officer notes</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\"><em>{{officer_notes}}</em></td></tr>\n  </table>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#BE123C;font-weight:800;\">Outstanding follow-ups ({{followups_overdue_count}} overdue)</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#FFF1F2;border:1px solid #FECDD3;border-radius:6px;\">{{{followups_html}}}</div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">{{{disease_intel_html}}}</td></tr>\n\n<tr><td style=\"padding:0 28px 14px;\">\n  <div style=\"background:#BE123C;border-radius:8px;padding:14px 16px;text-align:center;\">\n    <a href=\"{{console_url}}\" style=\"color:#FFFFFF;font-size:14px;font-weight:700;text-decoration:none;\">Take command of {{alert_code}} →</a>\n  </div>\n</td></tr>\n<tr><td style=\"padding:18px 28px 12px;background:#F1F5F9;border-top:1px solid #E2E8F0;\">\n  <p style=\"margin:0;font-size:11px;color:#475569;line-height:1.5;\">\n    <strong>{{country_name}} POE Sentinel</strong> · ESCALATION NOTICE · WHO IHR 2005 &amp; AFRO IDSR 3rd Ed. aligned.<br>\n    Alert <strong>{{alert_code}}</strong> · {{risk_level_label}} · fired {{alert_created_ago}} at {{alert_created_at}}.<br>\n    Open in console → <a href=\"{{console_url}}\" style=\"color:#1D4ED8;text-decoration:none;font-weight:600;\">{{console_url}}</a>\n  </p>\n</td></tr>\n<tr><td style=\"padding:8px 28px 18px;background:#F1F5F9;\">\n  <p style=\"margin:0;font-size:10px;color:#64748B;line-height:1.4;\">\n    This is a transactional public-health alert generated by the national surveillance pipeline. Do not reply; coordinate through the escalation ladder.<br>\n    Generated {{now}} UTC · template {{alert_code}} · recipient action expected within {{ack_sla_hours}}h.\n  </p>\n</td></tr></table></td></tr></table></body></html>', 'ESCALATION — {{alert_code}}\n{{country_name}} · POE {{poe_code}} · escalated to {{routed_to_level}}\n\nDisease: {{disease_name}} ({{disease_who_category}}) · CFR {{disease_cfr_pct}}\nRisk: {{risk_level_label}} · IHR window: {{disease_ihr_notification}}\n{{followups_overdue_count}} of {{followups_count}} follow-ups overdue.\n\nDECISIONS EXPECTED\n 1. Acknowledge in console within {{ack_hours}}h (by {{ack_deadline}}).\n 2. Reassign owners for overdue follow-ups.\n 3. Authorise next-level escalation if appropriate.\n 4. Confirm isolation posture: {{disease_isolation}}.\n 5. Coordinate with WHO country office if Annex 2 threshold met.\n\nCASE: {{traveler_name}} · {{traveler_age}} · {{traveler_nationality}}\nDisposition: {{final_disposition}} ({{disposition_details}})\nNotes: {{officer_notes}}\n\nEscalation ladder: {{escalation_ladder}}\nOpen in console → {{console_url}}', '[\"PHEOC\", \"NATIONAL\", \"WHO\"]', 0, 1, '2026-04-21 18:15:56', '2026-04-21 18:15:56'),
(11, 'PHEIC_ADVISORY', 'EMAIL', '▣ PHEIC pathway · {{disease_name}} · {{country_name}} · IHR NFP 24h window', '<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"></head><body style=\"margin:0;padding:0;background:#EEF2F7;font-family:Arial,Helvetica,sans-serif;color:#0F172A;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#EEF2F7;padding:24px 12px;\"><tr><td align=\"center\"><table role=\"presentation\" width=\"640\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:640px;background:#FFFFFF;border-radius:10px;overflow:hidden;box-shadow:0 4px 16px rgba(15,23,42,0.08);\"><tr><td style=\"background:linear-gradient(135deg,#1E1B4B 0%,#3730A3 55%,#6D28D9 100%);padding:26px 28px;\">\n  <div style=\"font-size:11px;letter-spacing:0.22em;text-transform:uppercase;color:#DDD6FE;font-weight:700;\">IHR 2005 · PHEIC PATHWAY</div>\n  <div style=\"margin-top:6px;font-size:12px;color:#E0E7FF;font-weight:600;\">Public Health Emergency of International Concern — WHO coordination pathway.</div>\n  <div style=\"margin-top:12px;font-size:22px;font-weight:800;color:#FFFFFF;line-height:1.15;\">▣ {{alert_code}} — candidate PHEIC event</div>\n  <div style=\"margin-top:8px;font-size:13px;color:#DDD6FE;\">{{alert_title}}</div>\n</td></tr>\n\n<tr><td style=\"padding:22px 28px 0;\">\n  <p style=\"margin:0;font-size:13px;color:#0F172A;\">A suspected case consistent with a WHO Tier 1 always-notifiable disease has been recorded. Under IHR 2005 this may constitute a PHEIC. The national IHR NFP must complete the Annex 2 assessment and notify WHO within 24 hours of the event being known.</p>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#3730A3;font-weight:800;\">Why PHEIC path applies</div>\n  <ul style=\"margin:8px 0 0 20px;padding:0;font-size:13px;color:#0F172A;\">\n    <li style=\"margin:4px 0;\">Disease <strong>{{disease_name}}</strong> is classified {{disease_who_category}}.</li>\n    <li style=\"margin:4px 0;\">Historical CFR: {{disease_cfr_pct}}; incubation window: {{disease_incubation}}.</li>\n    <li style=\"margin:4px 0;\">Transmission: {{disease_transmission}} — plausible international spread via {{conveyance_type}} {{conveyance_id}}.</li>\n    <li style=\"margin:4px 0;\">Travel path: {{journey_start}} → {{embarkation_port}} → {{poe_code}}, {{country_name}}.</li>\n  </ul>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#3730A3;font-weight:800;\">WHO PHEIC workflow expected</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;background:#EEF2FF;border:1px solid #C7D2FE;border-radius:8px;\">\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#3730A3;font-weight:700;width:28%;\">0–24 h</td><td style=\"padding:8px 12px;font-size:12px;\">Complete Annex 2 assessment. Notify WHO via national IHR NFP.</td></tr>\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#3730A3;font-weight:700;\">24–48 h</td><td style=\"padding:8px 12px;font-size:12px;\">WHO risk assessment + follow-up questions; consider IHR Emergency Committee.</td></tr>\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#3730A3;font-weight:700;\">48 h+</td><td style=\"padding:8px 12px;font-size:12px;\">If 2+ Annex 2 criteria confirmed → WHO DG may declare PHEIC, issue temporary recommendations.</td></tr>\n  </table>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">{{{disease_intel_html}}}</td></tr>\n\n<tr><td style=\"padding:0 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#3730A3;font-weight:800;\">Case snapshot</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;border:1px solid #E2E8F0;border-radius:6px;background:#F8FAFC;\">\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Traveller</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;font-weight:700;\">{{traveler_name}} · {{traveler_age}} · {{traveler_gender}} · {{traveler_nationality}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Travel</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{travel_direction}} · {{journey_start}} → {{embarkation_port}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Conveyance · seat</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{conveyance_type}} {{conveyance_id}} · seat {{seat_number}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Arrival</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{arrival_datetime}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Syndrome</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{syndrome_classification}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Disposition</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{final_disposition}}</td></tr>\n  </table>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#3730A3;font-weight:800;\">Cross-border spread signal (travel history)</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#EEF2FF;border:1px solid #C7D2FE;border-radius:6px;\">{{{travel_html}}}</div>\n</td></tr>\n\n<tr><td style=\"padding:20px 28px 14px;\">\n  <div style=\"background:#3730A3;border-radius:8px;padding:14px 16px;text-align:center;\">\n    <a href=\"{{console_url}}\" style=\"color:#FFFFFF;font-size:14px;font-weight:700;text-decoration:none;\">Open PHEIC assessment workflow →</a>\n  </div>\n</td></tr>\n<tr><td style=\"padding:18px 28px 12px;background:#F1F5F9;border-top:1px solid #E2E8F0;\">\n  <p style=\"margin:0;font-size:11px;color:#475569;line-height:1.5;\">\n    <strong>{{country_name}} POE Sentinel</strong> · PHEIC · IHR 2005 · WHO IHR 2005 &amp; AFRO IDSR 3rd Ed. aligned.<br>\n    Alert <strong>{{alert_code}}</strong> · {{risk_level_label}} · fired {{alert_created_ago}} at {{alert_created_at}}.<br>\n    Open in console → <a href=\"{{console_url}}\" style=\"color:#1D4ED8;text-decoration:none;font-weight:600;\">{{console_url}}</a>\n  </p>\n</td></tr>\n<tr><td style=\"padding:8px 28px 18px;background:#F1F5F9;\">\n  <p style=\"margin:0;font-size:10px;color:#64748B;line-height:1.4;\">\n    This is a transactional public-health alert generated by the national surveillance pipeline. Do not reply; coordinate through the escalation ladder.<br>\n    Generated {{now}} UTC · template {{alert_code}} · recipient action expected within {{ack_sla_hours}}h.\n  </p>\n</td></tr></table></td></tr></table></body></html>', 'PHEIC ADVISORY — {{alert_code}}\n{{country_name}} · POE {{poe_code}} · suspected {{disease_name}}\n\nUnder IHR 2005 this may constitute a Public Health Emergency of International Concern.\nNational IHR NFP must complete the Annex 2 assessment and notify WHO within 24 hours.\n\nDISEASE: {{disease_name}} ({{disease_who_category}})\nCFR {{disease_cfr_pct}} · Incubation {{disease_incubation}}\nTransmission: {{disease_transmission}}\nTravel path: {{journey_start}} → {{embarkation_port}} → {{poe_code}}\nConveyance: {{conveyance_type}} {{conveyance_id}} seat {{seat_number}}\n\nTIMELINE\n 0–24 h  Annex 2 assessment → WHO IHR notification\n 24–48 h WHO risk assessment / Emergency Committee consideration\n 48 h+   Possible PHEIC declaration + temporary recommendations\n\nOpen PHEIC workflow → {{console_url}}', '[\"NATIONAL\", \"WHO\"]', 0, 1, '2026-04-21 18:15:56', '2026-04-21 18:15:56'),
(12, 'ALERT_CLOSED', 'EMAIL', '✓ CLOSED · {{alert_code}} · {{disease_name}} · {{final_disposition}} · by {{closed_by_name}}', '<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"></head><body style=\"margin:0;padding:0;background:#EEF2F7;font-family:Arial,Helvetica,sans-serif;color:#0F172A;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#EEF2F7;padding:24px 12px;\"><tr><td align=\"center\"><table role=\"presentation\" width=\"640\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:640px;background:#FFFFFF;border-radius:10px;overflow:hidden;box-shadow:0 4px 16px rgba(15,23,42,0.08);\"><tr><td style=\"background:linear-gradient(135deg,#064E3B 0%,#047857 55%,#10B981 100%);padding:26px 28px;\">\n  <div style=\"font-size:11px;letter-spacing:0.22em;text-transform:uppercase;color:#A7F3D0;font-weight:700;\">ALERT RESOLVED &amp; CLOSED</div>\n  <div style=\"margin-top:6px;font-size:12px;color:#D1FAE5;font-weight:600;\">The alert has been formally closed. This notice is the closure record.</div>\n  <div style=\"margin-top:12px;font-size:22px;font-weight:800;color:#FFFFFF;line-height:1.15;\">✓ {{alert_code}} closed</div>\n  <div style=\"margin-top:8px;font-size:13px;color:#A7F3D0;\">{{alert_title}}</div>\n</td></tr>\n\n<tr><td style=\"padding:22px 28px 0;\">\n  <p style=\"margin:0;font-size:13px;color:#0F172A;\">This alert has been closed at {{alert_closed_at}} by <strong>{{closed_by_name}}</strong>. Review the summary below and raise any concern before the record is archived at the next digest cycle.</p>\n</td></tr>\n\n<tr><td style=\"padding:16px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#047857;font-weight:800;\">Closure record</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;background:#ECFDF5;border:1px solid #A7F3D0;border-radius:6px;\">\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#065F46;\">Alert</td><td style=\"padding:8px 12px;font-size:12px;text-align:right;font-weight:700;\">{{alert_code}}</td></tr>\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#065F46;\">Closed by</td><td style=\"padding:8px 12px;font-size:12px;text-align:right;font-weight:700;\">{{closed_by_name}}</td></tr>\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#065F46;\">Closed at</td><td style=\"padding:8px 12px;font-size:12px;text-align:right;\">{{alert_closed_at}}</td></tr>\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#065F46;vertical-align:top;\">Close reason</td><td style=\"padding:8px 12px;font-size:12px;text-align:right;\">{{close_reason}}</td></tr>\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#065F46;\">Risk at closure</td><td style=\"padding:8px 12px;font-size:12px;text-align:right;\">{{risk_level_label}}</td></tr>\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#065F46;\">Final disposition</td><td style=\"padding:8px 12px;font-size:12px;text-align:right;\">{{final_disposition}} — {{disposition_details}}</td></tr>\n    <tr><td style=\"padding:8px 12px;font-size:12px;color:#065F46;\">Outcome</td><td style=\"padding:8px 12px;font-size:12px;text-align:right;\">{{screening_outcome}}</td></tr>\n  </table>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#047857;font-weight:800;\">Case summary</div>\n  <p style=\"margin:6px 0 0;font-size:13px;color:#0F172A;\">{{summary}}</p>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#047857;font-weight:800;\">Follow-up status at closure ({{followups_count}})</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#ECFDF5;border:1px solid #A7F3D0;border-radius:6px;\">{{{followups_html}}}</div>\n  <p style=\"margin:6px 0 0;font-size:12px;color:#047857;\">If {{followups_overdue_count}} &gt; 0 — this alert closed with outstanding follow-ups. A data-quality review may follow.</p>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#047857;font-weight:800;\">Disease residual risk</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:6px;font-size:12px;color:#0F172A;\">\n    <p style=\"margin:0 0 6px;\"><strong>{{disease_name}}</strong> · incubation {{disease_incubation}} · transmission: {{disease_transmission}}.</p>\n    <p style=\"margin:0;\">Contacts should continue under monitoring through the incubation window even after alert closure. If anyone develops symptoms: re-open under a new alert.</p>\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:20px 28px 14px;\">\n  <div style=\"background:#047857;border-radius:8px;padding:14px 16px;text-align:center;\">\n    <a href=\"{{console_url}}\" style=\"color:#FFFFFF;font-size:14px;font-weight:700;text-decoration:none;\">View final record for {{alert_code}} →</a>\n  </div>\n</td></tr>\n<tr><td style=\"padding:18px 28px 12px;background:#F1F5F9;border-top:1px solid #E2E8F0;\">\n  <p style=\"margin:0;font-size:11px;color:#475569;line-height:1.5;\">\n    <strong>{{country_name}} POE Sentinel</strong> · ALERT CLOSED · WHO IHR 2005 &amp; AFRO IDSR 3rd Ed. aligned.<br>\n    Alert <strong>{{alert_code}}</strong> · {{risk_level_label}} · fired {{alert_created_ago}} at {{alert_created_at}}.<br>\n    Open in console → <a href=\"{{console_url}}\" style=\"color:#1D4ED8;text-decoration:none;font-weight:600;\">{{console_url}}</a>\n  </p>\n</td></tr>\n<tr><td style=\"padding:8px 28px 18px;background:#F1F5F9;\">\n  <p style=\"margin:0;font-size:10px;color:#64748B;line-height:1.4;\">\n    This is a transactional public-health alert generated by the national surveillance pipeline. Do not reply; coordinate through the escalation ladder.<br>\n    Generated {{now}} UTC · template {{alert_code}} · recipient action expected within {{ack_sla_hours}}h.\n  </p>\n</td></tr></table></td></tr></table></body></html>', 'ALERT CLOSED — {{alert_code}}\n{{country_name}} · POE {{poe_code}}\nClosed by {{closed_by_name}} at {{alert_closed_at}}\n\nReason: {{close_reason}}\nFinal disposition: {{final_disposition}} — {{disposition_details}}\nOutcome: {{screening_outcome}}\nSummary: {{summary}}\n\nFollow-ups at closure: {{followups_count}} seeded · {{followups_overdue_count}} overdue\n(If any remained overdue at closure → data-quality review may follow.)\n\nRESIDUAL RISK — {{disease_name}}\n · Incubation: {{disease_incubation}}\n · Transmission: {{disease_transmission}}\nContinue contact monitoring through incubation window. Re-open under a new alert if symptoms develop.\n\nOpen record → {{console_url}}', '[\"DISTRICT\", \"PHEOC\", \"NATIONAL\"]', 0, 1, '2026-04-21 18:15:56', '2026-04-21 18:15:56'),
(229, 'ALERT_CASE_FILE', 'EMAIL', '🗂 CASE FILE · {{alert_code}} · {{traveler_name}} · {{disease_name}} · disposition {{final_disposition}}', '<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"></head><body style=\"margin:0;padding:0;background:#EEF2F7;font-family:Arial,Helvetica,sans-serif;color:#0F172A;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#EEF2F7;padding:24px 12px;\"><tr><td align=\"center\"><table role=\"presentation\" width=\"640\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:640px;background:#FFFFFF;border-radius:10px;overflow:hidden;box-shadow:0 4px 16px rgba(15,23,42,0.08);\"><tr><td style=\"background:linear-gradient(135deg,#134E4A 0%,#0F766E 55%,#14B8A6 100%);padding:24px 28px;\">\n  <div style=\"font-size:11px;letter-spacing:0.22em;text-transform:uppercase;color:#CCFBF1;font-weight:700;\">CASE FILE · dispatch to response partners</div>\n  <div style=\"margin-top:6px;font-size:12px;color:#99F6E4;font-weight:600;\">Traveller dispositioned — case file forwarded for continuity of care / contact tracing.</div>\n  <div style=\"margin-top:10px;font-size:22px;font-weight:800;color:#FFFFFF;line-height:1.2;\">🗂 {{alert_code}} · {{disease_name}}</div>\n  <div style=\"margin-top:6px;font-size:13px;color:#CCFBF1;\">{{summary}}</div>\n</td></tr>\n\n<tr><td style=\"padding:22px 28px 0;\">\n  <p style=\"margin:0;font-size:13px;color:#0F172A;\">This is the <strong>complete case dispatch package</strong> for receiving teams (DISTRICT + PHEOC + receiving hospital + contact tracers). It contains every field captured at {{poe_code}} so you can receive, isolate, treat, investigate and trace without re-interviewing the traveller.</p>\n</td></tr>\n\n<tr><td style=\"padding:16px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#0F766E;font-weight:800;\">1 · IDENTIFICATION</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;border:1px solid #CCFBF1;border-radius:6px;background:#F0FDFA;\">\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#115E59;\">Name · Age · Gender · DOB</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;font-weight:700;\">{{traveler_name}} · {{traveler_age}} · {{traveler_gender}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#115E59;\">Nationality</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{traveler_nationality}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#115E59;\">Occupation</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{traveler_occupation}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#115E59;\">Residence country</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{traveler_residence}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#115E59;\">Contact · phone / email</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{traveler_phone}} · {{traveler_email}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#115E59;\">Emergency contact</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{emergency_contact}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#115E59;\">Destination in {{country_name}}</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{destination_district}} · {{destination_address}}</td></tr>\n  </table>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#0F766E;font-weight:800;\">2 · TRAVEL HISTORY</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;border:1px solid #CCFBF1;border-radius:6px;background:#F0FDFA;\">\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#115E59;\">Direction · purpose · stay</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{travel_direction}} · {{purpose_of_travel}} · {{length_of_stay}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#115E59;\">Journey start</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{journey_start}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#115E59;\">Embarkation port / city</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{embarkation_port}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#115E59;\">Conveyance · seat</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{conveyance_type}} {{conveyance_id}} · seat {{seat_number}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#115E59;\">Arrival → departure</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{arrival_datetime}} → {{departure_datetime}}</td></tr>\n  </table>\n  <div style=\"margin-top:8px;padding:10px 12px;background:#F0FDFA;border-left:3px solid #14B8A6;border-radius:4px;\">\n    <div style=\"font-size:11px;text-transform:uppercase;color:#115E59;font-weight:700;\">Countries visited / transited</div>\n    <div style=\"margin-top:4px;\">{{{travel_html}}}</div>\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#0F766E;font-weight:800;\">3 · CLINICAL FINDINGS</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;border:1px solid #CCFBF1;border-radius:6px;background:#F0FDFA;\">\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#115E59;\">Triage · general appearance</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;font-weight:700;\">{{triage_category}} · {{general_appearance}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#115E59;\">Emergency signs present</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;font-weight:700;\">{{emergency_signs}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#115E59;\">Syndromic classification</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{syndrome_classification}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#115E59;\">Assigned risk</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;font-weight:700;\">{{case_risk_level}}</td></tr>\n    {{{vitals_html}}}\n  </table>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#0F766E;font-weight:800;\">4 · SYMPTOMS · {{symptoms_count}}</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F0FDFA;border:1px solid #CCFBF1;border-radius:6px;\">{{{symptoms_html}}}</div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#0F766E;font-weight:800;\">5 · EXPOSURES</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F0FDFA;border:1px solid #CCFBF1;border-radius:6px;\">{{{exposures_html}}}</div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#0F766E;font-weight:800;\">6 · DIFFERENTIAL · {{suspected_count}} ranked</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F0FDFA;border:1px solid #CCFBF1;border-radius:6px;\">{{{suspected_html}}}</div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">{{{disease_intel_html}}}</td></tr>\n\n<tr><td style=\"padding:0 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#0F766E;font-weight:800;\">7 · SAMPLES COLLECTED · {{samples_count}}</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F0FDFA;border:1px solid #CCFBF1;border-radius:6px;\">{{{samples_html}}}</div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#0F766E;font-weight:800;\">8 · DISPOSITION &amp; OFFICER NOTES</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F0FDFA;border:1px solid #CCFBF1;border-radius:6px;\">\n    <p style=\"margin:0 0 6px;font-size:13px;\"><strong>Final disposition:</strong> {{final_disposition}}</p>\n    <p style=\"margin:0 0 6px;font-size:13px;\"><strong>Detail:</strong> {{disposition_details}}</p>\n    <p style=\"margin:0 0 6px;font-size:13px;\"><strong>Outcome:</strong> {{screening_outcome}} · <strong>follow-up:</strong> {{followup_required}} @ {{followup_level}}</p>\n    <p style=\"margin:10px 0 0;font-size:13px;color:#0F172A;\"><strong>Officer notes:</strong><br><em>{{officer_notes}}</em></p>\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#0F766E;font-weight:800;\">9 · ACTIONS TAKEN AT POE</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F0FDFA;border:1px solid #CCFBF1;border-radius:6px;\">{{{sec_actions_html}}}</div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#0F766E;font-weight:800;\">10 · FOLLOW-UPS EXPECTED ({{followups_count}} · {{followups_overdue_count}} overdue)</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#F0FDFA;border:1px solid #CCFBF1;border-radius:6px;\">{{{followups_html}}}</div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#0F766E;font-weight:800;\">11 · CONTINUITY OF CARE · what receiving teams must do</div>\n  <ul style=\"margin:8px 0 0 20px;padding:0;font-size:13px;color:#0F172A;\">\n    <li style=\"margin:5px 0;\">Re-verify identity on arrival using the initials/anonymous code above.</li>\n    <li style=\"margin:5px 0;\">Maintain isolation posture per disease: <strong>{{disease_isolation}}</strong>. PPE: {{disease_ppe}}.</li>\n    <li style=\"margin:5px 0;\">Collect any missing specimens: {{disease_specimens}}.</li>\n    <li style=\"margin:5px 0;\">Initiate/continue the {{followups_count}} seeded RTSL-14 follow-ups; blocks_closure flags matter.</li>\n    <li style=\"margin:5px 0;\">Trace contacts per disease incubation window: {{disease_incubation}}.</li>\n    <li style=\"margin:5px 0;\">Notify {{routed_to_level}} + national IHR NFP per: {{disease_ihr_notification}}.</li>\n  </ul>\n</td></tr>\n\n<tr><td style=\"padding:20px 28px 14px;\">\n  <div style=\"background:#0F766E;border-radius:8px;padding:14px 16px;text-align:center;\">\n    <a href=\"{{console_url}}\" style=\"color:#FFFFFF;font-size:14px;font-weight:700;text-decoration:none;\">Open full case file in console →</a>\n  </div>\n</td></tr>\n<tr><td style=\"padding:18px 28px 12px;background:#F1F5F9;border-top:1px solid #E2E8F0;\">\n  <p style=\"margin:0;font-size:11px;color:#475569;line-height:1.5;\">\n    <strong>{{country_name}} POE Sentinel</strong> · CASE-FILE DISPATCH · WHO IHR 2005 &amp; AFRO IDSR 3rd Ed. aligned.<br>\n    Alert <strong>{{alert_code}}</strong> · {{risk_level_label}} · fired {{alert_created_ago}} at {{alert_created_at}}.<br>\n    Open in console → <a href=\"{{console_url}}\" style=\"color:#1D4ED8;text-decoration:none;font-weight:600;\">{{console_url}}</a>\n  </p>\n</td></tr>\n<tr><td style=\"padding:8px 28px 18px;background:#F1F5F9;\">\n  <p style=\"margin:0;font-size:10px;color:#64748B;line-height:1.4;\">\n    This is a transactional public-health alert generated by the national surveillance pipeline. Do not reply; coordinate through the escalation ladder.<br>\n    Generated {{now}} UTC · template {{alert_code}} · recipient action expected within {{ack_sla_hours}}h.\n  </p>\n</td></tr></table></td></tr></table></body></html>', 'CASE FILE — DISPATCH PACKAGE\n{{alert_code}} · {{country_name}} · POE {{poe_code}} → routed_to {{routed_to_level}}\nDisease: {{disease_name}} ({{disease_who_category}}) · CFR {{disease_cfr_pct}}\n\nIDENTIFICATION\n · Traveller: {{traveler_name}} · {{traveler_age}} · {{traveler_gender}} · {{traveler_nationality}}\n · Occupation: {{traveler_occupation}}\n · Residence: {{traveler_residence}}\n · Contact: {{traveler_phone}} / {{traveler_email}}\n · Emergency contact: {{emergency_contact}}\n · Destination: {{destination_district}} ({{destination_address}})\n\nTRAVEL\n · Direction {{travel_direction}} · purpose {{purpose_of_travel}} · stay {{length_of_stay}}\n · Journey start: {{journey_start}} · embarkation: {{embarkation_port}}\n · Conveyance: {{conveyance_type}} {{conveyance_id}} seat {{seat_number}}\n · Arrival → departure: {{arrival_datetime}} → {{departure_datetime}}\n\nCLINICAL\n · Triage: {{triage_category}} · appearance: {{general_appearance}} · emergency signs: {{emergency_signs}}\n · Syndrome: {{syndrome_classification}} · assigned risk {{case_risk_level}}\n\nDISPOSITION\n · {{final_disposition}} — {{disposition_details}}\n · Outcome: {{screening_outcome}} · follow-up {{followup_required}} @ {{followup_level}}\n · Officer notes: {{officer_notes}}\n\nDISEASE INTEL\n · Incubation: {{disease_incubation}} · transmission: {{disease_transmission}}\n · PPE: {{disease_ppe}} · isolation: {{disease_isolation}}\n · IHR: {{disease_ihr_notification}}\n · Case def: {{disease_case_definition}}\n · Differential: {{disease_differential}}\n · Specimens to collect: {{disease_specimens}}\n\nFollow-ups: {{followups_count}} seeded · {{followups_overdue_count}} overdue\nSamples: {{samples_count}}\nOpen in console → {{console_url}}', '[\"DISTRICT\", \"PHEOC\", \"NATIONAL\"]', 0, 1, '2026-04-21 18:15:56', '2026-04-21 18:15:56');
INSERT INTO `notification_templates` (`id`, `template_code`, `channel`, `subject_template`, `body_html_template`, `body_text_template`, `applicable_levels`, `is_ai_enhanced`, `is_active`, `created_at`, `updated_at`) VALUES
(230, 'NATIONAL_INTELLIGENCE', 'EMAIL', '◉ {{country_name}} intel · silent {{silent_poes_count}} · stuck {{stuck_alerts_count}} · overdue {{overdue_followups_count}}', '<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"></head><body style=\"margin:0;padding:0;background:#EEF2F7;font-family:Arial,Helvetica,sans-serif;color:#0F172A;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#EEF2F7;padding:24px 12px;\"><tr><td align=\"center\"><table role=\"presentation\" width=\"640\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:640px;background:#FFFFFF;border-radius:10px;overflow:hidden;box-shadow:0 4px 16px rgba(15,23,42,0.08);\"><tr><td style=\"background:linear-gradient(135deg,#0C0A36 0%,#1E1B4B 50%,#1E40AF 100%);padding:26px 28px;\">\n  <div style=\"font-size:11px;letter-spacing:0.22em;text-transform:uppercase;color:#BFDBFE;font-weight:700;\">{{country_name}} · NATIONAL POE INTELLIGENCE BRIEF</div>\n  <div style=\"margin-top:6px;font-size:12px;color:#DBEAFE;\">Issued every 72 hours · IntelligenceEngine v1 · all POEs, all districts, all alerts.</div>\n  <div style=\"margin-top:12px;font-size:22px;font-weight:800;color:#FFFFFF;line-height:1.2;\">◉ National intelligence digest</div>\n</td></tr>\n\n<tr><td style=\"padding:22px 28px 0;\">\n  <p style=\"margin:0;font-size:13px;color:#0F172A;\">{{narrative}}</p>\n</td></tr>\n\n<tr><td style=\"padding:16px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#1E40AF;font-weight:800;\">1 · Silent POEs (no submission in the last 24h)</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#EFF6FF;border:1px solid #BFDBFE;border-radius:6px;\">\n    <p style=\"margin:0 0 6px;font-size:12px;color:#1E3A8A;\"><strong>{{silent_poes_count}} POE(s) silent.</strong> A silent POE either has no border traffic — or the duty officer is not logging.</p>\n    {{{silent_poes_html}}}\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#1E40AF;font-weight:800;\">2 · Unsubmitted pipelines (&gt;3 days unsynced)</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#EFF6FF;border:1px solid #BFDBFE;border-radius:6px;\">\n    <p style=\"margin:0 0 6px;font-size:12px;color:#1E3A8A;\"><strong>{{unsubmitted_poes_count}} POE(s)</strong> have offline data that has not reached the server. This breaks country-wide visibility.</p>\n    {{{unsubmitted_poes_html}}}\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#1E40AF;font-weight:800;\">3 · Dormant accounts (no login in the last 14 days)</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#EFF6FF;border:1px solid #BFDBFE;border-radius:6px;\">\n    <p style=\"margin:0 0 6px;font-size:12px;color:#1E3A8A;\"><strong>{{dormant_accounts_count}} officer account(s)</strong> are dormant. Credential hygiene + roster refresh recommended.</p>\n    {{{dormant_accounts_html}}}\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#1E40AF;font-weight:800;\">4 · Stuck alerts (open &gt;SLA · not acknowledged)</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#EFF6FF;border:1px solid #BFDBFE;border-radius:6px;\">\n    <p style=\"margin:0 0 6px;font-size:12px;color:#B91C1C;font-weight:700;\">{{stuck_alerts_count}} alert(s) stuck.</p>\n    {{{stuck_alerts_html}}}\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#1E40AF;font-weight:800;\">5 · Overdue follow-ups (blocking closure)</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#EFF6FF;border:1px solid #BFDBFE;border-radius:6px;\">\n    <p style=\"margin:0 0 6px;font-size:12px;color:#B91C1C;font-weight:700;\">{{overdue_followups_count}} follow-up action(s) past their window.</p>\n    {{{overdue_followups_html}}}\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#1E40AF;font-weight:800;\">6 · Case spikes &amp; cluster signals</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#EFF6FF;border:1px solid #BFDBFE;border-radius:6px;\">\n    <p style=\"margin:0 0 6px;font-size:12px;color:#1E3A8A;\"><strong>{{case_spikes_count}}</strong> anomalies detected vs. rolling 14-day baseline.</p>\n    {{{case_spikes_html}}}\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#1E40AF;font-weight:800;\">7 · Executive read-out &amp; recommendations</div>\n  <ul style=\"margin:8px 0 0 20px;padding:0;font-size:13px;color:#0F172A;\">\n    <li style=\"margin:5px 0;\">Reach out to every silent POE listed above within 24h.</li>\n    <li style=\"margin:5px 0;\">Contact officers from dormant accounts; confirm roster is correct.</li>\n    <li style=\"margin:5px 0;\">Re-assign ownership for stuck alerts and overdue follow-ups.</li>\n    <li style=\"margin:5px 0;\">Investigate any cluster signal — contact DHO of the affected district.</li>\n    <li style=\"margin:5px 0;\">Verify Annex 2 pipeline works end-to-end — any suspected Tier 1 event must be notified to WHO within 24h.</li>\n  </ul>\n</td></tr>\n\n<tr><td style=\"padding:20px 28px 14px;\">\n  <div style=\"background:#1E40AF;border-radius:8px;padding:14px 16px;text-align:center;\">\n    <a href=\"{{console_url}}\" style=\"color:#FFFFFF;font-size:14px;font-weight:700;text-decoration:none;\">Open national intelligence console →</a>\n  </div>\n</td></tr>\n<tr><td style=\"padding:18px 28px 14px;background:#F1F5F9;border-top:1px solid #E2E8F0;\">\n  <p style=\"margin:0;font-size:11px;color:#475569;line-height:1.5;\">\n    <strong>{{country_name}} POE Sentinel</strong> · INTELLIGENCE · EVERY 72h · WHO IHR 2005 + AFRO IDSR 2021 + 7-1-7 framework.<br>\n    Digest generated {{now}} for window ending {{now_date}}.<br>\n    Open dashboard → <a href=\"{{console_url}}\" style=\"color:#1D4ED8;text-decoration:none;font-weight:600;\">{{console_url}}</a>\n  </p>\n</td></tr></table></td></tr></table></body></html>', '{{country_name}} POE SENTINEL — NATIONAL INTELLIGENCE BRIEF\nIssued {{now}} (every 72h)\n\n{{narrative}}\n\n1. Silent POEs ({{silent_poes_count}})\n2. Unsubmitted pipelines ({{unsubmitted_poes_count}})\n3. Dormant officer accounts ({{dormant_accounts_count}})\n4. Stuck alerts ({{stuck_alerts_count}})\n5. Overdue follow-ups ({{overdue_followups_count}})\n6. Case spikes vs 14-day baseline ({{case_spikes_count}})\n\nEXECUTIVE ACTIONS\n · Reach out to every silent POE within 24h\n · Contact dormant officers; verify roster\n · Re-assign owners for stuck alerts + overdue follow-ups\n · Investigate cluster signals with affected DHOs\n · Verify Annex 2 pipeline — Tier 1 must notify WHO in 24h\n\nOpen national intelligence console → {{console_url}}', '[\"NATIONAL\", \"WHO\"]', 0, 1, '2026-04-21 18:15:56', '2026-04-21 18:15:56'),
(231, 'RESPONDER_INFO_REQUEST', 'EMAIL', '◈ Info request · {{alert_code}} · {{disease_name}} · please respond 24h', '<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"></head><body style=\"margin:0;padding:0;background:#EEF2F7;font-family:Arial,Helvetica,sans-serif;color:#0F172A;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#EEF2F7;padding:24px 12px;\"><tr><td align=\"center\"><table role=\"presentation\" width=\"640\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:640px;background:#FFFFFF;border-radius:10px;overflow:hidden;box-shadow:0 4px 16px rgba(15,23,42,0.08);\"><tr><td style=\"background:linear-gradient(135deg,#B45309 0%,#D97706 60%,#FBBF24 100%);padding:24px 28px;\">\n  <div style=\"font-size:11px;letter-spacing:0.18em;text-transform:uppercase;color:#FEF3C7;font-weight:700;\">EXTERNAL RESPONDER · INFO REQUEST</div>\n  <div style=\"margin-top:6px;font-size:12px;color:#FEF9C3;\">The POE needs a direct answer from you before proceeding.</div>\n  <div style=\"margin-top:12px;font-size:22px;font-weight:800;color:#FFFFFF;line-height:1.2;\">◈ Information requested · {{alert_code}}</div>\n  <div style=\"margin-top:8px;font-size:13px;color:#FEF3C7;\">You have been routed as a responder on this case.</div>\n</td></tr>\n\n<tr><td style=\"padding:22px 28px 0;\">\n  <p style=\"margin:0;font-size:13px;color:#0F172A;\">You are receiving this because a POE Sentinel case has routed a query to your inbox. The case summary and the specific question(s) follow. Reply to this email with the information requested — your response is logged into the case file automatically.</p>\n</td></tr>\n\n<tr><td style=\"padding:16px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#B45309;font-weight:800;\">What we need to know</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#FFFBEB;border:1px solid #FDE68A;border-radius:6px;\">\n    <ul style=\"margin:0;padding-left:18px;font-size:13px;color:#0F172A;\">\n      <li style=\"margin:4px 0;\">Has this traveller been seen in your facility / district / network before?</li>\n      <li style=\"margin:4px 0;\">Is the case consistent with anything you are currently investigating?</li>\n      <li style=\"margin:4px 0;\">Any outbreak / cluster context you can share?</li>\n      <li style=\"margin:4px 0;\">Can you confirm that contacts listed below can be reached?</li>\n      <li style=\"margin:4px 0;\">Any specific clinical observation, lab result, or epi detail to add?</li>\n    </ul>\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#B45309;font-weight:800;\">Case at a glance</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:8px;border:1px solid #E2E8F0;border-radius:6px;background:#F8FAFC;\">\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Alert</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;font-weight:700;\">{{alert_code}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Disease</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{disease_name}} · {{disease_who_category}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Risk</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;font-weight:700;\">{{risk_level_label}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Country · POE · district</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{country_name}} · {{poe_code}} · {{district_code}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Traveller</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{traveler_name}} · {{traveler_age}} · {{traveler_gender}} · {{traveler_nationality}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Destination in country</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{destination_district}} · {{destination_address}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Syndrome · disposition</td><td style=\"padding:6px 12px;font-size:12px;text-align:right;\">{{syndrome_classification}} · {{final_disposition}}</td></tr>\n  </table>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#B45309;font-weight:800;\">Disease context (for your situational awareness)</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#FFFBEB;border:1px solid #FDE68A;border-radius:6px;font-size:12px;color:#0F172A;\">\n    <p style=\"margin:0 0 4px;\"><strong>CFR:</strong> {{disease_cfr_pct}} · <strong>Incubation:</strong> {{disease_incubation}}.</p>\n    <p style=\"margin:0 0 4px;\"><strong>Transmission:</strong> {{disease_transmission}}.</p>\n    <p style=\"margin:0 0 4px;\"><strong>Isolation posture:</strong> {{disease_isolation}}.</p>\n    <p style=\"margin:0;\"><strong>Differential:</strong> {{disease_differential}}.</p>\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#B45309;font-weight:800;\">Travel context</div>\n  <div style=\"margin-top:8px;padding:12px 14px;background:#FFFBEB;border:1px solid #FDE68A;border-radius:6px;\">\n    <p style=\"margin:0 0 4px;font-size:12px;\">{{travel_direction}} · {{conveyance_type}} {{conveyance_id}} seat {{seat_number}} · arrival {{arrival_datetime}}</p>\n    {{{travel_html}}}\n  </div>\n</td></tr>\n\n<tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#B45309;font-weight:800;\">How to reply</div>\n  <ul style=\"margin:8px 0 0 20px;padding:0;font-size:13px;color:#0F172A;\">\n    <li style=\"margin:4px 0;\">Reply directly to this email — the response is appended to the case file.</li>\n    <li style=\"margin:4px 0;\">Or open {{console_url}} and record a note on {{alert_code}}.</li>\n    <li style=\"margin:4px 0;\">Please respond within <strong>24 hours</strong>. Silence delays the national response.</li>\n  </ul>\n</td></tr>\n\n<tr><td style=\"padding:20px 28px 14px;\">\n  <div style=\"background:#D97706;border-radius:8px;padding:14px 16px;text-align:center;\">\n    <a href=\"{{console_url}}\" style=\"color:#FFFFFF;font-size:14px;font-weight:700;text-decoration:none;\">Respond on {{alert_code}} →</a>\n  </div>\n</td></tr>\n<tr><td style=\"padding:18px 28px 12px;background:#F1F5F9;border-top:1px solid #E2E8F0;\">\n  <p style=\"margin:0;font-size:11px;color:#475569;line-height:1.5;\">\n    <strong>{{country_name}} POE Sentinel</strong> · RESPONDER INFO REQUEST · RTSL 14 early-response framework + WHO AFRO IDSR 2021.<br>\n    Alert <strong>{{alert_code}}</strong> · fired {{alert_created_ago}} at {{alert_created_at}}.<br>\n    Open in console → <a href=\"{{console_url}}\" style=\"color:#1D4ED8;text-decoration:none;font-weight:600;\">{{console_url}}</a>\n  </p>\n</td></tr></table></td></tr></table></body></html>', 'EXTERNAL RESPONDER — INFO REQUEST\n{{alert_code}} · {{country_name}} · POE {{poe_code}}\n\nWe need a direct answer from you on this case.\n\nQUESTIONS\n · Has this traveller been seen in your facility before?\n · Any current investigation / outbreak context?\n · Contacts below reachable?\n · Any extra clinical / lab / epi detail?\n\nCASE\n · Disease: {{disease_name}} ({{disease_who_category}}) · CFR {{disease_cfr_pct}}\n · Risk: {{risk_level_label}}\n · Traveller: {{traveler_name}} · {{traveler_age}} · {{traveler_gender}} · {{traveler_nationality}}\n · Destination: {{destination_district}} · {{destination_address}}\n · Syndrome: {{syndrome_classification}} · disposition {{final_disposition}}\n\nTRAVEL: {{travel_direction}} · {{conveyance_type}} {{conveyance_id}} seat {{seat_number}} · arrival {{arrival_datetime}}\nIncubation: {{disease_incubation}} · transmission: {{disease_transmission}}\n\nRespond to this email OR {{console_url}} within 24h.', '[\"DISTRICT\", \"PHEOC\", \"NATIONAL\", \"WHO\"]', 0, 1, '2026-04-21 18:15:56', '2026-04-21 18:15:56'),
(256, 'AUTH_WELCOME', 'EMAIL', '{{app_name}} · Your account is ready, {{full_name}}', '<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"></head><body style=\"margin:0;padding:0;background:#EEF2F7;font-family:Arial,Helvetica,sans-serif;color:#0F172A;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#EEF2F7;padding:24px 12px;\"><tr><td align=\"center\"><table role=\"presentation\" width=\"600\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:600px;background:#FFFFFF;border-radius:10px;overflow:hidden;box-shadow:0 4px 16px rgba(15,23,42,0.08);\"><tr><td style=\"background:linear-gradient(135deg,#064e3b 0%,#047857 55%,#10b981 100%);padding:24px 28px;\">\n  <div style=\"font-size:11px;letter-spacing:0.18em;text-transform:uppercase;color:#A7F3D0;font-weight:700;\">{{app_name}} · Welcome</div>\n  <div style=\"margin-top:10px;font-size:22px;font-weight:800;color:#fff;\">Hello, {{full_name}}</div>\n  <div style=\"margin-top:6px;font-size:13px;color:#D1FAE5;\">Your account is now active.</div>\n</td></tr>\n<tr><td style=\"padding:22px 28px 6px;font-size:13px;\">\n  <p style=\"margin:0 0 12px;\">Welcome to {{app_name}}. Your account has been created and is ready to use.</p>\n  <ul style=\"margin:0 0 12px 18px;padding:0;\">\n    <li>Sign in at <a href=\"{{console_url}}\" style=\"color:#047857;\">{{console_url}}</a></li>\n    <li>Turn on Two-Factor Authentication in Settings → Security</li>\n    <li>Review your assignments and notification preferences</li>\n  </ul>\n</td></tr><tr><td style=\"padding:16px 28px;background:#F1F5F9;border-top:1px solid #E2E8F0;\">\n  <p style=\"margin:0;font-size:11px;color:#475569;line-height:1.55;\">\n    <strong>{{app_name}}</strong> · Welcome notification<br>\n    If this wasn\'t you, contact your administrator immediately and reset your password.<br>\n    Generated {{now}} UTC from {{ip}}.\n  </p>\n</td></tr></table></td></tr></table></body></html>', 'Hello {{full_name}},\n\nYour {{app_name}} account is active.\nSign in at {{console_url}}\n\nIP {{ip}} · {{now}} UTC', '[\"SELF\"]', 0, 1, '2026-04-21 21:10:51', '2026-04-21 21:10:51'),
(257, 'AUTH_INVITATION', 'EMAIL', 'You have been invited to {{app_name}} as {{role_display}}', '<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"></head><body style=\"margin:0;padding:0;background:#EEF2F7;font-family:Arial,Helvetica,sans-serif;color:#0F172A;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#EEF2F7;padding:24px 12px;\"><tr><td align=\"center\"><table role=\"presentation\" width=\"600\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:600px;background:#FFFFFF;border-radius:10px;overflow:hidden;box-shadow:0 4px 16px rgba(15,23,42,0.08);\"><tr><td style=\"background:linear-gradient(135deg,#0c1b3a 0%,#1e293b 55%,#334155 100%);padding:24px 28px;\">\n  <div style=\"font-size:11px;letter-spacing:0.18em;text-transform:uppercase;color:#cbd5e1;font-weight:700;\">{{app_name}} · Invitation</div>\n  <div style=\"margin-top:10px;font-size:22px;font-weight:800;color:#fff;\">You\'ve been invited</div>\n  <div style=\"margin-top:6px;font-size:13px;color:#cbd5e1;\">{{inviter}} invited you as <strong style=\"color:#fff;\">{{role_display}}</strong>.</div>\n</td></tr>\n<tr><td style=\"padding:22px 28px 0;font-size:13px;\">\n  <p style=\"margin:0 0 10px;\">Hello {{full_name}},</p>\n  <p style=\"margin:0 0 10px;\">Click the button below to set your password and activate your {{app_name}} account. This invitation expires in <strong>{{expires_in}}</strong>.</p>\n</td></tr><tr><td style=\"padding:18px 28px 10px;\">\n  <div style=\"background:#0F172A;border-radius:8px;padding:14px 16px;text-align:center;\">\n    <a href=\"{{invite_url}}\" style=\"color:#FFFFFF;font-size:14px;font-weight:700;text-decoration:none;\">Accept invitation →</a>\n  </div>\n  <p style=\"margin:10px 0 0;font-size:11px;color:#64748B;text-align:center;\">Or paste this link into your browser:<br><span style=\"word-break:break-all;\">{{invite_url}}</span></p>\n</td></tr><tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#475569;font-weight:700;\">Device + location</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:6px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:8px;\">\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">IP address</td><td style=\"padding:6px 12px;text-align:right;font-size:12px;font-family:ui-monospace,monospace;\">{{ip}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">User agent</td><td style=\"padding:6px 12px;text-align:right;font-size:12px;\">{{user_agent}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Time (UTC)</td><td style=\"padding:6px 12px;text-align:right;font-size:12px;\">{{now}}</td></tr>\n  </table>\n</td></tr><tr><td style=\"padding:16px 28px;background:#F1F5F9;border-top:1px solid #E2E8F0;\">\n  <p style=\"margin:0;font-size:11px;color:#475569;line-height:1.55;\">\n    <strong>{{app_name}}</strong> · Admin invitation<br>\n    If this wasn\'t you, contact your administrator immediately and reset your password.<br>\n    Generated {{now}} UTC from {{ip}}.\n  </p>\n</td></tr></table></td></tr></table></body></html>', 'Hello {{full_name}},\n\n{{inviter}} has invited you to join {{app_name}} as {{role_display}}.\nAccept here (expires in {{expires_in}}): {{invite_url}}', '[\"SELF\"]', 0, 1, '2026-04-21 21:10:51', '2026-04-21 21:10:51'),
(258, 'AUTH_VERIFY_EMAIL', 'EMAIL', 'Verify your {{app_name}} email', '<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"></head><body style=\"margin:0;padding:0;background:#EEF2F7;font-family:Arial,Helvetica,sans-serif;color:#0F172A;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#EEF2F7;padding:24px 12px;\"><tr><td align=\"center\"><table role=\"presentation\" width=\"600\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:600px;background:#FFFFFF;border-radius:10px;overflow:hidden;box-shadow:0 4px 16px rgba(15,23,42,0.08);\"><tr><td style=\"background:linear-gradient(135deg,#0369a1 0%,#0284c7 55%,#0ea5e9 100%);padding:24px 28px;\">\n  <div style=\"font-size:11px;letter-spacing:0.18em;text-transform:uppercase;color:#bae6fd;font-weight:700;\">{{app_name}} · Email verification</div>\n  <div style=\"margin-top:10px;font-size:22px;font-weight:800;color:#fff;\">Verify your email</div>\n</td></tr>\n<tr><td style=\"padding:22px 28px 0;font-size:13px;\">\n  <p style=\"margin:0 0 10px;\">Hello {{full_name}},</p>\n  <p style=\"margin:0 0 10px;\">Confirm that <strong>{{email}}</strong> belongs to you. This link is valid for <strong>{{expires_in}}</strong>.</p>\n</td></tr><tr><td style=\"padding:18px 28px 10px;\">\n  <div style=\"background:#0369a1;border-radius:8px;padding:14px 16px;text-align:center;\">\n    <a href=\"{{verify_url}}\" style=\"color:#FFFFFF;font-size:14px;font-weight:700;text-decoration:none;\">Verify email address →</a>\n  </div>\n  <p style=\"margin:10px 0 0;font-size:11px;color:#64748B;text-align:center;\">Or paste this link into your browser:<br><span style=\"word-break:break-all;\">{{verify_url}}</span></p>\n</td></tr><tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#475569;font-weight:700;\">Device + location</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:6px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:8px;\">\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">IP address</td><td style=\"padding:6px 12px;text-align:right;font-size:12px;font-family:ui-monospace,monospace;\">{{ip}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">User agent</td><td style=\"padding:6px 12px;text-align:right;font-size:12px;\">{{user_agent}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Time (UTC)</td><td style=\"padding:6px 12px;text-align:right;font-size:12px;\">{{now}}</td></tr>\n  </table>\n</td></tr><tr><td style=\"padding:16px 28px;background:#F1F5F9;border-top:1px solid #E2E8F0;\">\n  <p style=\"margin:0;font-size:11px;color:#475569;line-height:1.55;\">\n    <strong>{{app_name}}</strong> · Email verification<br>\n    If this wasn\'t you, contact your administrator immediately and reset your password.<br>\n    Generated {{now}} UTC from {{ip}}.\n  </p>\n</td></tr></table></td></tr></table></body></html>', 'Hello {{full_name}},\nVerify your email: {{verify_url}}\nExpires in {{expires_in}}.', '[\"SELF\"]', 0, 1, '2026-04-21 21:10:51', '2026-04-21 21:10:51'),
(259, 'AUTH_PASSWORD_RESET', 'EMAIL', 'Reset your {{app_name}} password', '<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"></head><body style=\"margin:0;padding:0;background:#EEF2F7;font-family:Arial,Helvetica,sans-serif;color:#0F172A;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#EEF2F7;padding:24px 12px;\"><tr><td align=\"center\"><table role=\"presentation\" width=\"600\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:600px;background:#FFFFFF;border-radius:10px;overflow:hidden;box-shadow:0 4px 16px rgba(15,23,42,0.08);\"><tr><td style=\"background:linear-gradient(135deg,#b45309 0%,#d97706 55%,#f59e0b 100%);padding:24px 28px;\">\n  <div style=\"font-size:11px;letter-spacing:0.18em;text-transform:uppercase;color:#fef3c7;font-weight:700;\">{{app_name}} · Password reset</div>\n  <div style=\"margin-top:10px;font-size:22px;font-weight:800;color:#fff;\">Reset your password</div>\n</td></tr>\n<tr><td style=\"padding:22px 28px 0;font-size:13px;\">\n  <p style=\"margin:0 0 10px;\">Hello {{full_name}},</p>\n  <p style=\"margin:0 0 10px;\">We received a request to reset the password for <strong>{{email}}</strong>. Click below to pick a new password. This link is valid for <strong>{{expires_in}}</strong>.</p>\n  <p style=\"margin:0 0 10px;color:#92400E;\"><strong>Didn\'t request this?</strong> Ignore this email — your password will not change.</p>\n</td></tr><tr><td style=\"padding:18px 28px 10px;\">\n  <div style=\"background:#b45309;border-radius:8px;padding:14px 16px;text-align:center;\">\n    <a href=\"{{reset_url}}\" style=\"color:#FFFFFF;font-size:14px;font-weight:700;text-decoration:none;\">Reset password →</a>\n  </div>\n  <p style=\"margin:10px 0 0;font-size:11px;color:#64748B;text-align:center;\">Or paste this link into your browser:<br><span style=\"word-break:break-all;\">{{reset_url}}</span></p>\n</td></tr><tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#475569;font-weight:700;\">Device + location</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:6px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:8px;\">\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">IP address</td><td style=\"padding:6px 12px;text-align:right;font-size:12px;font-family:ui-monospace,monospace;\">{{ip}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">User agent</td><td style=\"padding:6px 12px;text-align:right;font-size:12px;\">{{user_agent}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Time (UTC)</td><td style=\"padding:6px 12px;text-align:right;font-size:12px;\">{{now}}</td></tr>\n  </table>\n</td></tr><tr><td style=\"padding:16px 28px;background:#F1F5F9;border-top:1px solid #E2E8F0;\">\n  <p style=\"margin:0;font-size:11px;color:#475569;line-height:1.55;\">\n    <strong>{{app_name}}</strong> · Password reset request<br>\n    If this wasn\'t you, contact your administrator immediately and reset your password.<br>\n    Generated {{now}} UTC from {{ip}}.\n  </p>\n</td></tr></table></td></tr></table></body></html>', 'Reset link (expires in {{expires_in}}): {{reset_url}}\nIf you didn\'t request this, ignore this email.', '[\"SELF\"]', 0, 1, '2026-04-21 21:10:51', '2026-04-21 21:10:51'),
(260, 'AUTH_PASSWORD_CHANGED', 'EMAIL', '{{app_name}} · Your password was changed', '<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"></head><body style=\"margin:0;padding:0;background:#EEF2F7;font-family:Arial,Helvetica,sans-serif;color:#0F172A;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#EEF2F7;padding:24px 12px;\"><tr><td align=\"center\"><table role=\"presentation\" width=\"600\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:600px;background:#FFFFFF;border-radius:10px;overflow:hidden;box-shadow:0 4px 16px rgba(15,23,42,0.08);\"><tr><td style=\"background:linear-gradient(135deg,#064e3b 0%,#047857 55%,#10b981 100%);padding:24px 28px;\">\n  <div style=\"font-size:11px;letter-spacing:0.18em;text-transform:uppercase;color:#a7f3d0;font-weight:700;\">{{app_name}} · Password changed</div>\n  <div style=\"margin-top:10px;font-size:22px;font-weight:800;color:#fff;\">Your password was changed</div>\n</td></tr>\n<tr><td style=\"padding:22px 28px 0;font-size:13px;\">\n  <p style=\"margin:0 0 10px;\">Hello {{full_name}},</p>\n  <p style=\"margin:0 0 10px;\">Your {{app_name}} password was changed at <strong>{{now}} UTC</strong>. All existing sessions have been revoked — you\'ll need to sign in again on every device.</p>\n  <p style=\"margin:0 0 10px;color:#b91c1c;\"><strong>Wasn\'t you?</strong> Reset your password immediately and contact your administrator.</p>\n</td></tr><tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#475569;font-weight:700;\">Device + location</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:6px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:8px;\">\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">IP address</td><td style=\"padding:6px 12px;text-align:right;font-size:12px;font-family:ui-monospace,monospace;\">{{ip}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">User agent</td><td style=\"padding:6px 12px;text-align:right;font-size:12px;\">{{user_agent}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Time (UTC)</td><td style=\"padding:6px 12px;text-align:right;font-size:12px;\">{{now}}</td></tr>\n  </table>\n</td></tr><tr><td style=\"padding:16px 28px;background:#F1F5F9;border-top:1px solid #E2E8F0;\">\n  <p style=\"margin:0;font-size:11px;color:#475569;line-height:1.55;\">\n    <strong>{{app_name}}</strong> · Security notice<br>\n    If this wasn\'t you, contact your administrator immediately and reset your password.<br>\n    Generated {{now}} UTC from {{ip}}.\n  </p>\n</td></tr></table></td></tr></table></body></html>', 'Your password was changed at {{now}} UTC from {{ip}}.\nIf this wasn\'t you, reset immediately and contact an administrator.', '[\"SELF\"]', 0, 1, '2026-04-21 21:10:51', '2026-04-21 21:10:51'),
(261, 'AUTH_TWOFA_ENABLED', 'EMAIL', '{{app_name}} · 2FA enabled on your account', '<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"></head><body style=\"margin:0;padding:0;background:#EEF2F7;font-family:Arial,Helvetica,sans-serif;color:#0F172A;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#EEF2F7;padding:24px 12px;\"><tr><td align=\"center\"><table role=\"presentation\" width=\"600\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:600px;background:#FFFFFF;border-radius:10px;overflow:hidden;box-shadow:0 4px 16px rgba(15,23,42,0.08);\"><tr><td style=\"background:linear-gradient(135deg,#064e3b 0%,#047857 55%,#10b981 100%);padding:24px 28px;\">\n  <div style=\"font-size:11px;letter-spacing:0.18em;text-transform:uppercase;color:#a7f3d0;font-weight:700;\">{{app_name}} · 2FA enabled</div>\n  <div style=\"margin-top:10px;font-size:22px;font-weight:800;color:#fff;\">Two-factor authentication is on</div>\n</td></tr>\n<tr><td style=\"padding:22px 28px 0;font-size:13px;\">\n  <p style=\"margin:0 0 10px;\">Hello {{full_name}},</p>\n  <p style=\"margin:0 0 10px;\">2FA (TOTP) is now required whenever you sign in. Keep your authenticator app (Google Authenticator, 1Password, Authy) safe, and <strong>store your recovery codes offline</strong>.</p>\n</td></tr><tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#475569;font-weight:700;\">Device + location</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:6px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:8px;\">\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">IP address</td><td style=\"padding:6px 12px;text-align:right;font-size:12px;font-family:ui-monospace,monospace;\">{{ip}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">User agent</td><td style=\"padding:6px 12px;text-align:right;font-size:12px;\">{{user_agent}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Time (UTC)</td><td style=\"padding:6px 12px;text-align:right;font-size:12px;\">{{now}}</td></tr>\n  </table>\n</td></tr><tr><td style=\"padding:16px 28px;background:#F1F5F9;border-top:1px solid #E2E8F0;\">\n  <p style=\"margin:0;font-size:11px;color:#475569;line-height:1.55;\">\n    <strong>{{app_name}}</strong> · Security event · 2FA<br>\n    If this wasn\'t you, contact your administrator immediately and reset your password.<br>\n    Generated {{now}} UTC from {{ip}}.\n  </p>\n</td></tr></table></td></tr></table></body></html>', 'Two-factor authentication was enabled on your account at {{now}} UTC.', '[\"SELF\"]', 0, 1, '2026-04-21 21:10:51', '2026-04-21 21:10:51'),
(262, 'AUTH_TWOFA_DISABLED', 'EMAIL', '⚠ {{app_name}} · 2FA was disabled on your account', '<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"></head><body style=\"margin:0;padding:0;background:#EEF2F7;font-family:Arial,Helvetica,sans-serif;color:#0F172A;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#EEF2F7;padding:24px 12px;\"><tr><td align=\"center\"><table role=\"presentation\" width=\"600\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:600px;background:#FFFFFF;border-radius:10px;overflow:hidden;box-shadow:0 4px 16px rgba(15,23,42,0.08);\"><tr><td style=\"background:linear-gradient(135deg,#7f1d1d 0%,#b91c1c 55%,#dc2626 100%);padding:24px 28px;\">\n  <div style=\"font-size:11px;letter-spacing:0.18em;text-transform:uppercase;color:#fecaca;font-weight:700;\">{{app_name}} · 2FA disabled</div>\n  <div style=\"margin-top:10px;font-size:22px;font-weight:800;color:#fff;\">Two-factor authentication was disabled</div>\n</td></tr>\n<tr><td style=\"padding:22px 28px 0;font-size:13px;\">\n  <p style=\"margin:0 0 10px;\">Hello {{full_name}},</p>\n  <p style=\"margin:0 0 10px;\"><strong>2FA is now OFF</strong> on your {{app_name}} account. Your account is now only protected by your password.</p>\n  <p style=\"margin:0 0 10px;color:#b91c1c;\"><strong>Wasn\'t you?</strong> Reset your password immediately and enable 2FA again.</p>\n</td></tr><tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#475569;font-weight:700;\">Device + location</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:6px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:8px;\">\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">IP address</td><td style=\"padding:6px 12px;text-align:right;font-size:12px;font-family:ui-monospace,monospace;\">{{ip}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">User agent</td><td style=\"padding:6px 12px;text-align:right;font-size:12px;\">{{user_agent}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Time (UTC)</td><td style=\"padding:6px 12px;text-align:right;font-size:12px;\">{{now}}</td></tr>\n  </table>\n</td></tr><tr><td style=\"padding:16px 28px;background:#F1F5F9;border-top:1px solid #E2E8F0;\">\n  <p style=\"margin:0;font-size:11px;color:#475569;line-height:1.55;\">\n    <strong>{{app_name}}</strong> · Security warning · 2FA removed<br>\n    If this wasn\'t you, contact your administrator immediately and reset your password.<br>\n    Generated {{now}} UTC from {{ip}}.\n  </p>\n</td></tr></table></td></tr></table></body></html>', 'Two-factor authentication was DISABLED at {{now}} UTC from {{ip}}.', '[\"SELF\"]', 0, 1, '2026-04-21 21:10:51', '2026-04-21 21:10:51'),
(263, 'AUTH_NEW_LOGIN_DEVICE', 'EMAIL', '{{app_name}} · New sign-in on {{device_label}}', '<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"></head><body style=\"margin:0;padding:0;background:#EEF2F7;font-family:Arial,Helvetica,sans-serif;color:#0F172A;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#EEF2F7;padding:24px 12px;\"><tr><td align=\"center\"><table role=\"presentation\" width=\"600\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:600px;background:#FFFFFF;border-radius:10px;overflow:hidden;box-shadow:0 4px 16px rgba(15,23,42,0.08);\"><tr><td style=\"background:linear-gradient(135deg,#0369a1 0%,#0284c7 55%,#0ea5e9 100%);padding:24px 28px;\">\n  <div style=\"font-size:11px;letter-spacing:0.18em;text-transform:uppercase;color:#bae6fd;font-weight:700;\">{{app_name}} · New sign-in</div>\n  <div style=\"margin-top:10px;font-size:22px;font-weight:800;color:#fff;\">Sign-in from a new device</div>\n</td></tr>\n<tr><td style=\"padding:22px 28px 0;font-size:13px;\">\n  <p style=\"margin:0 0 10px;\">Hello {{full_name}},</p>\n  <p style=\"margin:0 0 10px;\">Your account was signed in from a device we haven\'t seen in the last 30 days.</p>\n  <p style=\"margin:0 0 10px;\"><strong>Device:</strong> {{device_label}}</p>\n</td></tr><tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#475569;font-weight:700;\">Device + location</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:6px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:8px;\">\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">IP address</td><td style=\"padding:6px 12px;text-align:right;font-size:12px;font-family:ui-monospace,monospace;\">{{ip}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">User agent</td><td style=\"padding:6px 12px;text-align:right;font-size:12px;\">{{user_agent}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Time (UTC)</td><td style=\"padding:6px 12px;text-align:right;font-size:12px;\">{{now}}</td></tr>\n  </table>\n</td></tr><tr><td style=\"padding:16px 28px;background:#F1F5F9;border-top:1px solid #E2E8F0;\">\n  <p style=\"margin:0;font-size:11px;color:#475569;line-height:1.55;\">\n    <strong>{{app_name}}</strong> · New sign-in notice<br>\n    If this wasn\'t you, contact your administrator immediately and reset your password.<br>\n    Generated {{now}} UTC from {{ip}}.\n  </p>\n</td></tr></table></td></tr></table></body></html>', 'New sign-in on {{device_label}} at {{now}} UTC from {{ip}}.\nIf this wasn\'t you, reset your password.', '[\"SELF\"]', 0, 1, '2026-04-21 21:10:51', '2026-04-21 21:10:51'),
(264, 'AUTH_ACCOUNT_LOCKED', 'EMAIL', '⚠ {{app_name}} · Account locked after failed sign-in attempts', '<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"></head><body style=\"margin:0;padding:0;background:#EEF2F7;font-family:Arial,Helvetica,sans-serif;color:#0F172A;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#EEF2F7;padding:24px 12px;\"><tr><td align=\"center\"><table role=\"presentation\" width=\"600\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:600px;background:#FFFFFF;border-radius:10px;overflow:hidden;box-shadow:0 4px 16px rgba(15,23,42,0.08);\"><tr><td style=\"background:linear-gradient(135deg,#7f1d1d 0%,#b91c1c 55%,#dc2626 100%);padding:24px 28px;\">\n  <div style=\"font-size:11px;letter-spacing:0.18em;text-transform:uppercase;color:#fecaca;font-weight:700;\">{{app_name}} · Account locked</div>\n  <div style=\"margin-top:10px;font-size:22px;font-weight:800;color:#fff;\">Your account is temporarily locked</div>\n</td></tr>\n<tr><td style=\"padding:22px 28px 0;font-size:13px;\">\n  <p style=\"margin:0 0 10px;\">Hello {{full_name}},</p>\n  <p style=\"margin:0 0 10px;\">We detected <strong>{{failed_count}}</strong> failed sign-in attempts on your account. Your account is locked until <strong>{{locked_until}}</strong>.</p>\n  <p style=\"margin:0 0 10px;\">If this wasn\'t you, we recommend resetting your password.</p>\n</td></tr><tr><td style=\"padding:14px 28px 0;\">\n  <div style=\"font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#475569;font-weight:700;\">Device + location</div>\n  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:6px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:8px;\">\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">IP address</td><td style=\"padding:6px 12px;text-align:right;font-size:12px;font-family:ui-monospace,monospace;\">{{ip}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">User agent</td><td style=\"padding:6px 12px;text-align:right;font-size:12px;\">{{user_agent}}</td></tr>\n    <tr><td style=\"padding:6px 12px;font-size:12px;color:#475569;\">Time (UTC)</td><td style=\"padding:6px 12px;text-align:right;font-size:12px;\">{{now}}</td></tr>\n  </table>\n</td></tr><tr><td style=\"padding:16px 28px;background:#F1F5F9;border-top:1px solid #E2E8F0;\">\n  <p style=\"margin:0;font-size:11px;color:#475569;line-height:1.55;\">\n    <strong>{{app_name}}</strong> · Security event · lockout<br>\n    If this wasn\'t you, contact your administrator immediately and reset your password.<br>\n    Generated {{now}} UTC from {{ip}}.\n  </p>\n</td></tr></table></td></tr></table></body></html>', 'Your account is locked until {{locked_until}} after {{failed_count}} failed attempts from {{ip}}.', '[\"SELF\"]', 0, 1, '2026-04-21 21:10:51', '2026-04-21 21:10:51'),
(265, 'AUTH_SUSPENDED', 'EMAIL', '{{app_name}} · Account access suspended', '<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"></head><body style=\"margin:0;padding:0;background:#EEF2F7;font-family:Arial,Helvetica,sans-serif;color:#0F172A;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#EEF2F7;padding:24px 12px;\"><tr><td align=\"center\"><table role=\"presentation\" width=\"600\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:600px;background:#FFFFFF;border-radius:10px;overflow:hidden;box-shadow:0 4px 16px rgba(15,23,42,0.08);\"><tr><td style=\"background:linear-gradient(135deg,#7f1d1d 0%,#991b1b 55%,#b91c1c 100%);padding:24px 28px;\">\n  <div style=\"font-size:11px;letter-spacing:0.18em;text-transform:uppercase;color:#fecaca;font-weight:700;\">{{app_name}} · Access suspended</div>\n  <div style=\"margin-top:10px;font-size:22px;font-weight:800;color:#fff;\">Your account has been suspended</div>\n</td></tr>\n<tr><td style=\"padding:22px 28px 0;font-size:13px;\">\n  <p style=\"margin:0 0 10px;\">Hello {{full_name}},</p>\n  <p style=\"margin:0 0 10px;\">An administrator has suspended your access to {{app_name}}.</p>\n  <p style=\"margin:0 0 10px;\"><strong>Reason:</strong> {{reason}}</p>\n  <p style=\"margin:0 0 10px;\">If you believe this is a mistake, contact your administrator.</p>\n</td></tr><tr><td style=\"padding:16px 28px;background:#F1F5F9;border-top:1px solid #E2E8F0;\">\n  <p style=\"margin:0;font-size:11px;color:#475569;line-height:1.55;\">\n    <strong>{{app_name}}</strong> · Administrative action<br>\n    If this wasn\'t you, contact your administrator immediately and reset your password.<br>\n    Generated {{now}} UTC from {{ip}}.\n  </p>\n</td></tr></table></td></tr></table></body></html>', 'Your access to {{app_name}} has been suspended.\nReason: {{reason}}\nTime: {{now}} UTC', '[\"SELF\"]', 0, 1, '2026-04-21 21:10:51', '2026-04-21 21:10:51');

